import { getPitchRange } from "../appData.js";

export const level4 = {
  level: 4,
  title: "The Full Palette",
  subtitle: "From triad to pentatonic. Color, expression, freedom.",
  description:
    "You've mastered the triad — root, 3rd, 5th, deeply felt. Now we expand: a fourth note (D) unlocks stepwise motion, and a fifth (G) completes the Am pentatonic — the most universal scale in music. With five notes you can improvise over any song in the key of Am with no wrong notes. Along the way you'll explore major vs minor palettes, palette switching over chord changes, vowel shapes, breath-phrased melody, the expressive power of silence, groove absorption, sensory vocabulary building, genre feel shifts, syncopation, and body percussion layering. Building on Level 3's embodiment foundation, you now apply the hear-feel-choose cycle to five notes, multiple genres, and real-time improvisation. By the end, your five-note palette is a living, breathing musical vocabulary.",
  artists: "Khruangbin, Skinshape, Tommy Guerrero, DOPE LEMON",
  unlocks: "The Full Scale & Jumps (Level 5)",
  vocalPrep: "Before singing: 30 seconds of lip trills (brrr) or straw buzzes on a comfortable pitch, sliding gently up and down. Then 3 sighs (haaa) from high to low. This level reaches G4 — near your passaggio (the gear-shift between chest and head voice around A3-B3). The SOVT warm-up smooths that transition before you need it.",
  review: { label: "Level 3 Check-In", time: 5, exercises: ["ss-3-11", "ss-3-12"], prompt: "Sing a three-note conversation with triadic colors (ss-3-11). Then three moods over A-C-E (ss-3-12). Both fluid? Move on." },
  exercises: [

    // ─── PHASE 4: FOUR NOTES — ADDING THE STEP ───

    {
      id: "ss-4-1",
      time: 7,
      title: "Adding the Bridge — D",
      type: "vocal",
      what: "Four notes now: A, C, D, E. D sits between C and E — it's the bridge, the passing tone, the note that makes STEPWISE MOTION possible. Before D, you had to leap between C and E. Now you can walk: C-D-E or E-D-C. Smooth, connected, flowing.",
      setup: "Guitar. Drone on A. Metronome at 75 BPM.",
      steps: [
        { text: "Review your triad: sing A-C-E ascending, E-C-A descending, against the drone. Feel the leap between C and E — it's a gap, a jump, a skip. You've been jumping this gap for a while now. Today you fill it.", why: "Feeling the C-to-E gap before filling it makes the new note's purpose visceral. You'll understand WHY D matters because you'll feel the difference it makes." },
        { text: "Sing D against the drone. Hold it for 8 beats. Feel how D is different from the triad notes — it's less stable, more restless. D wants to move. It pulls toward C or toward E. It's a bridge, not a destination.", why: "D is the 4th scale degree — a passing tone that creates movement and tension. Unlike the stable root, 3rd, and 5th, D has an inherent pull that drives melodies forward. It's the oil that makes the engine run." },
        { text: "Now mute the drone. The silence hits — but D's echo is still in your ear and its vibration is still in your body. Hold both. Don't sing yet. For 3 seconds, keep D alive inside your head AND feel its ghost vibration — that restless hum between chest and throat. When both the pitch and the physical sensation are vivid, let it become sound again. Check with the pitch detector — did what came out match the D you were holding internally? This is the full scaffolded audiation cycle: play → absorb → mute → hold internally with body sensation → re-sing → check.", why: "Gordon's discrimination learning says you must HEAR a note externally before you can hold it internally. Muting the drone immediately after singing D gives you the purest version of this: the echo is fresh, your body remembers where D lived. Adding the body-sensation hold alongside the pitch hold gives you two channels sustaining the note — auditory AND somatic. Two channels are more reliable than one. The pitch detector check closes the loop." },
        { text: "Turn the drone back on. Sing D again — feel it against the root. Now a body check: where does D resonate in your body? D is restless in the body too — feel it between chest and throat, like A but lighter, more mobile. A sat deep behind the sternum. C buzzed in the throat and jaw. D lives between them — a vibration that's still partly chest but pulling upward, ready to move. It's the bridge note in your body just as it's the bridge note in your scale. If you can't feel the distinction yet, that's normal — try alternating: sing A (feel chest), then D (feel the shift upward), then A again. The contrast reveals D's address.", why: "Somatic mapping gives audiation a physical anchor. When you know D lives in a specific place in your body, you have TWO ways to find it: by ear (the interval from the drone) and by feel (the body location). Two pathways are more reliable than one. Your body map is growing: A = chest/sternum, C = throat/jaw, D = between chest and throat. Each note's physical address is determined by bone-conducted resonance pathways — your larynx transmits vibration differently at different frequencies, activating different body regions (Zamorano 2025)." },
        { text: "Walk the bridge: sing C-D-E slowly. Feel how D connects them — smooth, stepwise, no leap. As you step C-D-E, feel the vibration migrate smoothly upward through throat and chest — no jump, just a gentle rising. Then E-D-C, feeling it settle back down. Then the full walk: A-C-D-E ascending, E-D-C-A descending. The body walks with the melody — each step lands in a slightly different place.", why: "Before D, you had to leap between C and E. Now you can WALK. Stepwise motion is the most natural melodic movement — and the body mirrors it: resonance migrates smoothly instead of jumping." },
        { text: "Improvise with all four notes: A, C, D, E. Notice how D creates flow — melodies that felt angular with three notes now feel smoother. D is the glue between your triad tones. 2 minutes, free exploration.", why: "The addition of one passing tone transforms your melodic vocabulary from triadic leaps to flowing lines. This is a qualitative shift — your improvisations will sound more like 'real' melodies because stepwise motion is how most melodies work." },
        { text: "Try using D as a quick 'connecting' note — don't hold it, just pass through it between C and E. Then try holding D as a long note and feel its tension. Both approaches are valid tools. Record 2 minutes.", why: "Passing tones can be quick (connecting two stable notes) or sustained (creating tension). Learning both uses of D gives you options — smooth connection or intentional tension." }
      ],
      feel: "D should feel like a stepping stone between C and E — useful, purposeful, always moving. When you walk C-D-E, it should feel smooth and connected, like stepping stones across a stream instead of leaping over it.",
      wrong: "If D feels random or out of place, you're not hearing it in context. Always approach D from C or from E — feel how it bridges the gap. If you hold D for a long time and it feels uncomfortable, that's correct — D is a tension note. Let it resolve to C or E. If the new note feels weird or forced, that's proprioceptive recalibration — your body map is updating. Trust the recording over how it feels for the first few sessions.",
      sarah: "Gene, adding D is like learning the word 'and' — it connects everything. Your melodies just went from choppy phrases to flowing sentences. One note, and suddenly your four-note world sounds like music. End-of-exercise retrieval: set the guitar down, close your eyes for 30 seconds, then walk A-C-D-E from memory. Whatever you remember IS what you've internalized.",
      drone: { root: "Am", octave: 2, texture: "pure" },
      referencePitches: getPitchRange("A2", "E4"),
      pitchContour: true,
      metronome: 75,
      recorder: true
    },
    {
      id: "ss-4-2",
      time: 6,
      title: "Stepwise Wandering",
      type: "vocal",
      what: "Now that D bridges C and E, walk through your four notes using primarily stepwise motion: A-C-D-E-D-C-A. Each note leads gently to the next. No big leaps. Stepwise motion is the most natural melodic movement — it's how we sing intuitively.",
      setup: "Guitar. Metronome at 80 BPM. Optional backing track.",
      tracks: [{ name: "Khruangbin Style 80", src: "/khruangbin-style-80.mp3" }],
      steps: [
        { text: "Strum Am on autopilot. Sing the ascending walk: A-C-D-E. One note per beat, slow and deliberate. As you step from A to C, feel the vibration shift from chest to throat — the ache of the minor 3rd arriving in your jaw. As you reach D, notice it's lighter, more mobile, pulling upward. As you arrive at E, feel the resonance climb into the mask. Each step isn't just a pitch change — it's a body change. Then descend: E-D-C-A, feeling the vibration settle back down through throat to chest. Repeat 4 times.", why: "Stepwise ascending and descending is the most basic melodic exercise — and the most useful. The majority of notes in most melodies move by step, not by leap. Tracking the body-location shift as pitch moves makes each step a somatic event, not just an interval." },
        { text: "Now wander freely using mostly stepwise motion: A-C-D-C-D-E-D-C-A. Each note is adjacent to the last. No skipping. Let the melody meander like a path through the woods. Before each step, hear the next note forming — feel where it will land in your body before your voice arrives there. The drone is your compass — every note in your four-note palette has a specific distance from A. As you wander, you can FEEL that distance. D pulls differently from C, E opens differently from D. Let the drone tell you where you are.", why: "Constrained wandering — moving only to adjacent notes — produces surprisingly beautiful, flowing melodies. Folk traditions worldwide use this approach. The constraint creates natural, singable phrases. Pre-hearing each step before taking it transforms walking into intentional melodic composition." },
        { text: "Add occasional leaps for contrast: walk stepwise for 4-5 notes, then leap from A up to E (or E down to A). The leap feels dramatic because you've been stepping — and in your body, the vibration JUMPS from chest to mask instead of migrating gradually. Then return to walking and feel the smooth body-travel resume.", why: "Leaps are more powerful when they're rare. A melody that walks and walks and then suddenly leaps creates a moment of drama. The step-step-step-LEAP pattern is a fundamental melodic technique. The body feels the leap too — the resonance teleports instead of sliding." },
        { text: "Try walking over the backing track: let the Khruangbin groove shape your stepwise wandering. Walk in time with the beat, stepping through A-C-D-E at whatever pace the groove suggests. Before each step, hear the next note forming inside you — feel where it's gathering. A collects behind the sternum. C sits in the throat. D hovers between chest and throat. E opens into the mask. When both the pitch and the physical sensation are vivid, let your voice step to it. If autopilot kicks in and you're just running the scale without feeling the body-location shift, pause. Hear the next note. Feel its address. Then step. 2 minutes.", why: "The groove provides rhythmic context for your stepwise motion. Walking in time with a beat transforms academic scale walking into musical phrasing. The embodiment check — hearing and feeling each note before arriving — prevents the groove from lulling you into mechanical repetition." },
        { text: "Record 2 minutes of free stepwise wandering. Afterward, listen back — your four-note walks should sound like embryonic melodies. They ARE melodies, just simple ones.", why: "Recognizing your stepwise walks as real melodies builds confidence. You're not doing exercises — you're making music with four notes. The simplicity is the point." }
      ],
      feel: "This should feel like walking a gentle trail — each step leads naturally to the next, no effort required. The melody flows rather than jumps. When you're in the flow of stepwise motion, it should feel almost automatic.",
      wrong: "If you keep leaping (skipping from A to E without passing through C and D), you're reverting to triadic thinking. Deliberately step through every note between start and destination. Walk, don't jump.",
      sarah: "Gene, the psych-surf melodies you love are full of stepwise motion — those hypnotic, flowing vocal lines from Allah-Las and BALTHVS are mostly just walking through adjacent notes. This is where that sound comes from.",
      metronome: 80,
      referencePitches: getPitchRange("A2", "E4"),
      pitchContour: true,
      recorder: true
    },
    {
      id: "ss-4-3",
      time: 6,
      title: "Four-Note Conversation",
      type: "vocal",
      what: "Guitar-voice call and response with A, C, D, E. The conversation now has stepwise motion available — smoother, more melodic phrases. Notice how adding ONE note (D) transforms the conversation from triadic jumps to flowing lines.",
      setup: "Guitar. Metronome at 80 BPM.",
      steps: [
        { text: "Play a short guitar phrase using A, C, D, E — try a stepwise phrase like C-D-E-D (walking up and back). During the guitar call, listen with your whole body: feel your vocal response forming before you sing it. Where will it start — in the chest warmth of A, the throat-ache of C? Let the response crystallize inside, then answer with your voice.", why: "The conversation now has stepwise motion available. Guitar phrases sound smoother, voice responses can flow — the musical dialogue gains a new quality of connectedness. Feeling the response form before singing it bridges reaction and composition." },
        { text: "Make the guitar call use a LEAP (A up to E). Make the voice answer use STEPS (E-D-C-A walking down). Before singing, hear E forming in the mask — feel its brightness gathering behind the nose bridge. Then step down: E settles, D drops between chest and throat, C lands in the jaw with its ache, A arrives home in the sternum. The stepping-down response lets the vibration settle gradually from mask back to chest — a physical unwinding that mirrors the musical resolution.", why: "Mixing leaps and steps between call and response adds a new dimension to the dialogue. The body experiences the contrast too: leaps teleport the resonance, steps let it migrate. Pre-feeling the starting note before the descent makes the whole body journey intentional." },
        { text: "Reverse: voice calls with a stepwise phrase, guitar answers with a leap-based phrase. Then try matching: both use steps, or both use leaps. Feel how the conversation character changes — when both step, the dialogue feels intimate and close; when both leap, it feels bold and declarative.", why: "When both speakers use the same motion type, there's agreement. When they contrast, there's complementary tension. Both are musically valid — the choice is expressive." },
        { text: "Free conversation: 2 minutes, four notes, alternating guitar and voice. Let the phrases be 2-4 notes long — short enough to be clear, long enough to have contour. Before each voice response, take a breath and let the hear-feel-choose cycle run: hear the response, feel where it lives, know what it expresses. Then sing. Record it.", why: "Short phrases with clear contour are the building blocks of songwriting. The breath between call and response is a natural audiation window — use it to compose internally before speaking musically." },
        { text: "Compare this to your two-note conversations (ss-3-7). Notice how much more melodic the four-note version sounds — smoother, more song-like. That's what D added.", why: "Explicitly comparing your current ability to earlier exercises reveals your growth. Four notes with stepwise motion sounds dramatically more musical than two notes — and you built to it gradually." }
      ],
      feel: "This should feel noticeably more musical than the two-note conversations. The phrases flow, the responses have melodic shape, and the dialogue sounds like fragments of songs rather than rhythmic exercises.",
      wrong: "If you're still only using A and E (reverting to your comfortable two-note pair), consciously include C and D. The new notes are what make this phase different. If the phrases feel random, try starting each phrase by stepping from one note to its neighbor.",
      sarah: "Gene, notice how adding ONE note transformed the entire conversation. D is a small addition — but it's the difference between angular fragments and flowing melodies. Your four-note phrases are starting to sound like real music because they can WALK.",
      metronome: 80,
      referencePitches: getPitchRange("A2", "E4"),
      recorder: true,
      phraseForm: { pattern: "AB", barsPerSection: 2, labels: { A: "Guitar Call", B: "Voice Answer" } }
    },

    // ─── PHASE 5: FIVE NOTES — FULL PENTATONIC ───

    {
      id: "ss-4-4",
      time: 7,
      title: "The Full Palette — Adding G",
      type: "vocal",
      what: "Five notes: A, C, D, E, G. The Am pentatonic — the most universal scale in music. G is the highest note in your palette, the peak, the reach. Every culture on earth uses this five-note scale. With these five notes, you can improvise over ANY song in the key of Am. No wrong notes. Complete freedom.",
      setup: "Guitar. Drone on A. Metronome at 80 BPM.",
      steps: [
        { text: "Before starting: breathe in for 4 counts, then hum-sigh out for 6 counts. Repeat 3 times. G is the highest note in your palette — your vagus nerve may tighten the throat when you reach for it. This primes the laryngeal environment for the new range. Then review your four notes: sing A-C-D-E ascending, E-D-C-A descending against the drone. This is your known world. Now you're about to add the final note — the peak of the palette.", why: "The vagus nerve directly controls the vocal folds. Higher notes can trigger nervous system activation that constricts the throat. The hum-sigh primes the instrument. Reviewing the four-note palette before expanding it grounds you in familiar territory. Each addition has been gradual — root, 5th, 3rd, bridge. G is the capstone." },
        { text: "Sing G against the drone. Hold it for 8 beats. Feel the reach — G is the highest note in your palette, the farthest from home. It has a quality of uplift, of aspiration, of reaching for something. It's the peak of the mountain.", why: "G is the minor 7th — it creates a gentle tension that wants to resolve back down. It's the 'reach' note, the one that creates the most melodic interest when it leads back to familiar territory." },
        { text: "Now mute the drone. G's echo is in your ear — can you hold its 'reach' quality internally? It's the highest note in your palette, so it has a specific brightness, a specific tension. Feel where G's ghost vibration lingers — up near the forehead, the lightest resonance in your palette. Hold both: the pitch in your mind's ear AND the physical sensation near the brow. Sustain both for 3 seconds. When the pitch and the body sensation are both vivid, re-sing it. Check with the pitch detector. G is harder to hold than D was — it's farther from home, so the echo fades faster. But the scaffolding is the same: play → absorb → mute → hold with body sensation → re-sing → check.", why: "Each new note gets the same audiation scaffolding with somatic reinforcement. G is the most challenging note to hold internally because it's the farthest interval from the root (minor 7th). The forehead body-address gives you a second channel — even when the pitch echo fades, the body sensation can help you recover it." },
        { text: "Turn the drone back on. Hear A (the drone gives you the anchor). Now hear G internally without playing it — feel the distance from A up to G. That interval — root to minor 7th — has a specific character: a wide, reaching stretch. Can you feel that distance? Try to hear G forming from the anchor before you sing it. Then sing G. Check. The drone is your compass — G is measured from it.", why: "Interval audiation from an anchor is the key skill Gene identified as missing. The drone provides the tonal reference; the interval provides the distance. Together they give you a MAP to every note. You're not hearing G 'from nothing' — you're hearing it as 'this far from A.' That's how audiation actually works." },
        { text: "Body check: where does G resonate? G reaches toward the mask and forehead — the highest in your palette, the lightest vibration, the most 'lifted' sensation. While A buzzed deep behind the sternum and C sat in the throat, G climbs into the facial bones: the bridge of the nose, the cheeks, the area behind the eyes. Sing A, then G. Feel the vibration travel from chest to face — that's bone-conducted resonance following different pathways as the frequency rises. Your complete body map now has five addresses: A = chest/sternum, C = throat/jaw, D = between chest and throat, E = mask/nose bridge, G = forehead reach. Each note has a home in your body. When you know WHERE a note lives, you can find it without your ears — your body remembers.", why: "Building body-maps for each new note creates a physical vocabulary alongside the sonic one. Cross-cultural research on 1,938 participants (Nummenmaa 2024, PNAS) confirms these body maps are universal — not culturally learned, but hardwired. Low frequencies activate chest, higher frequencies activate face and head. When you know where G lives in your body, you can find it through two channels: ear (interval from drone) and body (physical sensation). This redundancy makes audiation more reliable. You now have the complete somatic map for the Am pentatonic — five body addresses that will serve as a second verification channel for every note you sing." },
        { text: "Sing the full Am pentatonic ascending: A-C-D-E-G. Then descending: G-E-D-C-A. One note per beat. Feel the complete palette — earth, blue, bridge, sky, peak. Five colors.", why: "The pentatonic scale is the most universal scale in human music — every culture on earth uses it independently. These five notes are hard-wired into human musical cognition. There are no dissonances, no wrong combinations." },
        { text: "Skip around freely — any note in any order. A-G-C-E-D. G-C-A-E-D. No pattern, no sequence, just exploring the full space. Feel how every combination works. No wrong notes.", why: "Free exploration of the pentatonic builds confidence that ANY combination of these notes sounds musical. This is the scale's magic — there are no bad choices, only different colors and contours." },
        { text: "2-minute eyes-closed freestyle with all five notes. No rules, no targets. Let your ear, your body, and your emotional instincts guide you through the full palette. As you move between notes, track the vibration traveling through your body — chest to throat to mask to forehead and back. Each note is a place you know by feel now, not just by pitch. Record it. This is your first full pentatonic improvisation.", why: "Extended freestyle on the pentatonic is a milestone — you now have enough notes for genuinely complex, song-like melodies. With body-mapping active, the improvisation has a somatic dimension: you're navigating a body geography, not just a pitch set." }
      ],
      feel: "Five notes should feel like unlocking a door — suddenly you have enough colors to paint real pictures. The pentatonic is the sweet spot: enough notes for infinite variety, few enough that every combination sounds good. Freedom without overwhelm.",
      wrong: "If the five notes feel like too many choices, you've ramped too fast. Go back to four notes (ss-4-1) for another session, or start your five-note freestyle by walking stepwise (A-C-D-E-G) rather than leaping randomly. The structure will guide you. VOCAL TIP: G is near your passaggio — the gear-shift zone where chest voice transitions toward head voice. If G cracks, flips, or sounds strained, try these three things: (1) NARROW THE VOWEL — as you go higher, let 'ah' become more like 'uh.' This tilts the vocal folds and makes the transition smoother. (2) THINK DOWN — imagine G is below you and you're stepping down onto it, not reaching up. This relaxes the muscles that squeeze when you 'reach.' (3) LESS AIR, NOT MORE — beginners push more air on high notes, which makes them crack. Try singing G QUIETER than E. The resonance carries the note, not the air pressure. If G still breaks, that's fine — you're at the edge of your current range, and edges move with practice.",
      sarah: "Gene, every artist you love lives in the pentatonic — Khruangbin, Skinshape, Allah-Las, Tinariwen, Tommy Guerrero. This five-note scale is the common language of psych-surf, desert blues, reggae, and soul. You now have the full palette. The rest of this level is about making it yours. If you've explored Vocal Level 6, this five-note freedom connects to the pentatonic sandbox there — same scale, same body map, different context.",
      drone: { root: "Am", octave: 2, texture: "warm" },
      referencePitches: getPitchRange("A2", "G4"),
      pitchContour: true,
      pianoKeys: { notes: ["A3", "C4", "D4", "E4", "G4"], label: "Am Pentatonic", range: ["A3", "G4"] },
      fretboard: { scale: "am-pentatonic", position: 1 },
      metronome: 80,
      recorder: true
    },
    {
      id: "ss-4-5",
      time: 7,
      title: "Pentatonic Rhythm Play",
      type: "vocal",
      what: "All five pentatonic notes with full rhythmic freedom. Apply everything you've learned: long holds, short bursts, syncopation, silence, dynamic shifts. Five notes and infinite rhythms. This is where the scale becomes a living, breathing musical vocabulary.",
      setup: "Guitar. Metronome at 80 BPM. Backing track.",
      tracks: [{ name: "Reggae One Drop 85", src: "/reggae-one-drop-85.mp3" }, { name: "Drums Only — Bossa 75", src: "/drums-bossa-75.mp3" }, { name: "Drums Only — Soul/Funk 90", src: "/drums-soul-funk-90.mp3" }],
      steps: [
        { text: "Play the backing track. Just LISTEN for 30 seconds with eyes closed. Feel where the groove lives in your body — the kick in your chest, the snare in your head-nod, the hi-hat in your breathing. When your body is moving with the groove, THEN pick up your instrument. This isn't patience — it's neural entrainment, priming your motor system through focused listening. Then strum Am on autopilot with the backing track. Sing pentatonic notes (A-C-D-E-G) using ONLY whole notes — one note per bar. Slow, deliberate, letting each note breathe. Before each note, run the full cycle: hear it in your head, feel where it will resonate in your body, sense what emotional color it carries — then let it become sound. At this tempo you have time for all three channels. A whole bar of chest-warmth feels completely different from a whole bar of mask-brightness.", why: "30 seconds of focused listening primes the motor system through neural entrainment — your brain starts rehearsing the groove before you play a note. Starting with whole notes forces intentional note choice. When each note lasts a full bar, the selection matters — you're composing in slow motion. With time to pre-hear, pre-feel, and pre-choose, each note arrives as a complete sensory event — pitch, body, emotion unified." },
        { text: "Before moving to quarter notes, try this: hear a short rhythmic phrase in your inner ear — just 2-3 pentatonic notes with a specific rhythm. Tap the rhythm on your knee. THEN sing it. Did the rhythm match what you heard inside? This is rhythmic audiation — hearing time and pitch together before they leave your mouth.", why: "Rhythmic audiation (Gordon Stage 6) is harder than pitch audiation alone — your inner ear must coordinate WHEN and WHAT simultaneously. Tapping first externalizes the rhythm so you can check your internal hearing against a physical output before adding pitch." },
        { text: "Speed up to quarter notes. Now four notes per bar — the pentatonic comes alive with rhythm. Try walking stepwise, then try leaping. Feel how rhythm transforms the scale from a list of notes into a flowing melody.", why: "Quarter notes add rhythmic motion. The pentatonic stops being a 'scale' and becomes a melodic language. Your brain must now coordinate pitch choice AND rhythmic placement simultaneously — a skill you've built gradually." },
        { text: "Try syncopation: land pentatonic notes on the offbeats, between the reggae groove's downbeats. Sing BETWEEN the guitar strums. Notice how offbeat notes feel physically different — there's a tension in your body between where the beat IS and where your voice IS. That displacement creates a buoyancy, a lift. The one-drop groove leaves space for you — fill it, and feel the body respond to the rhythmic tension.", why: "Offbeat pentatonic singing over reggae is one of the most natural musical combinations in your genre palette. The groove provides the skeleton, your voice provides the melody in the spaces. The physical sensation of displacement — body wanting to sync but voice deliberately floating — IS syncopation, felt somatically." },
        { text: "Dynamic variation: sing some pentatonic phrases loudly, others barely above a whisper. Let the dynamics follow the melody contour — ascend = louder, descend = softer. Or reverse. Or random. Use volume as a creative tool.", why: "Dynamics applied to a five-note palette creates the full illusion of complex melody. When pitch, rhythm, AND dynamics all vary, simple pentatonic phrases sound like fully composed melodies." },
        { text: "2-minute full freestyle: all five notes, any rhythm, any dynamic, over the backing track. Use silence. Use bursts. Use long tones. Use everything you've built. Record it.", why: "This is the synthesis exercise — combining every skill (rhythmic variety, dynamic range, pentatonic freedom) into a single extended improvisation. It should feel like you're writing a song in real time." }
      ],
      feel: "This should feel like PLAYING — not practicing, not exercising, but making music. The pentatonic over a reggae groove should feel as natural as breathing. If you're nodding your head and smiling, you're in the right place.",
      wrong: "If you're stuck on the same two or three notes, consciously reach for the ones you're avoiding. G and D often get neglected — include them deliberately until they feel as natural as A and E.",
      sarah: "Gene, this is the exercise where everything clicks — five notes, a reggae groove, and all the rhythmic and dynamic tools you've built. Skinshape's vocal lines are exactly this: pentatonic notes over a groove, with rhythm and dynamics doing the heavy lifting. You're there.",
      metronome: 80,
      referencePitches: getPitchRange("A2", "G4"),
      recorder: true
    },
    {
      id: "ss-4-6",
      time: 8,
      title: "Pentatonic Conversation",
      type: "vocal",
      what: "The full guitar-voice conversation with all 5 pentatonic notes. Guitar plays a short pentatonic phrase, voice answers with a pentatonic phrase. Now the conversation has full melodic range — contour, stepwise motion, leaps, emotional color. This is real improvisation.",
      setup: "Guitar. Metronome at 80 BPM. Backing track.",
      tracks: [{ name: "Khruangbin Style 80", src: "/khruangbin-style-80.mp3" }],
      steps: [
        { text: "Play a short pentatonic guitar phrase (Am pentatonic, frets 5-8 on the top strings). Keep it 3-5 notes. Then answer with your voice: sing a pentatonic phrase that responds to the guitar's contour and emotion. During the guitar call, the drone anchors you — from that anchor, feel your response forming before you sing it. Hear the intervals from the root. Which notes want to answer the guitar's question? Let them crystallize inside before they come out.", why: "The pentatonic conversation is the culmination of all your call-and-response work. With five notes, both guitar and voice have full melodic range — the conversation sounds like two musicians playing together. Using the drone as anchor while composing your response internally bridges the gap between reactive singing and audiated improvisation." },
        { text: "Try matching the guitar's emotional intent: if the guitar plays something gentle and stepwise, answer with something gentle. If the guitar plays something rhythmic and punchy, answer in kind. Use the full cycle: hear the guitar's intent, feel it land in your body — does the gentle call settle in your chest? Does the punchy call tighten your shoulders? — then choose a response that lives in the same body region and emotional temperature. Emotional matching creates coherent musical dialogue.", why: "Matching emotion between call and response creates musical coherence — the conversation has a mood. Feeling the call's body location and matching it in the response adds a somatic channel to the emotional matching — you're not just hearing the mood, you're feeling where it lives and responding from that same place." },
        { text: "Now try CONTRASTING: if the guitar plays high and fast (G-E-D), answer low and slow (A... C...). If the guitar is sparse, answer with a flurry. Contrast creates drama and keeps the conversation interesting.", why: "Contrast in call-and-response creates musical tension and release. A conversation where both speakers always agree is boring — a great musical dialogue has agreement AND surprise." },
        { text: "Extended free conversation: 3 minutes of alternating guitar and voice over the backing track. Let the phrases develop — start simple, let them grow more complex as you warm up. During each guitar call, let your response form as a whole-body event: hear the pitch, feel its body address, sense what it wants to express. When the response is vivid inside — not just a pitch but a felt intention — sing it. Some exchanges will be brief; others might extend into longer ideas.", why: "Extended conversation builds musical stamina and depth. Pre-forming the response as a unified pitch-body-emotion event makes each phrase arrive with more conviction. The longer you sustain the dialogue with this embodied attention, the more discoveries emerge." },
        { text: "Delayed response round: guitar plays a pentatonic call. Now count silently to 5 — hold the entire call vivid in your mind: the notes, the rhythm, the emotional color, the body locations it activated. Then respond. The 5-second gap transforms the conversation from reactive to audiated. Try 3 exchanges with the delay. Notice: does the delay change the QUALITY of your response? Many musicians find their delayed responses are more intentional, more musical.", why: "Systematically delaying the response forces your inner ear to carry the musical conversation alone for 5 seconds. This is pure audiation training embedded in a creative context. Choir directors use progressive gap-lengthening as their primary audiation tool — you're applying it to improvised conversation rather than drilled patterns." },
        { text: "Record the last 2 minutes. Listen back for the moment where guitar and voice were truly in conversation — where the response couldn't have existed without the specific call that preceded it. That's the magic moment.", why: "Identifying moments of genuine musical conversation trains you to recognize (and reproduce) the feeling of real-time musical dialogue. These moments are the seeds of your future songs." }
      ],
      feel: "This should feel like Khruangbin in your living room — Mark plays a pentatonic lick, Laura answers with her voice, the conversation flows naturally. Relaxed, groovy, responsive. Each phrase listens to what came before.",
      wrong: "If you're ignoring what the guitar just played and singing unrelated phrases, you're monologuing, not conversing. The voice answer should RESPOND to the guitar call — acknowledge it, develop it, contrast it, or complete it.",
      sarah: "Gene, Khruangbin does this constantly — Mark plays a pentatonic phrase, Laura answers. Their entire sound is this conversation. You're building the same instinct, with the same scale, over the same kind of groove. This IS the music you love, at its simplest and most essential.",
      metronome: 80,
      referencePitches: getPitchRange("A2", "G4"),
      recorder: true,
      phraseForm: { pattern: "AB", barsPerSection: 2, labels: { A: "Guitar Call", B: "Voice Answer" } }
    },
    {
      id: "ss-4-7",
      time: 8,
      title: "Free Exploration — Am Pentatonic",
      type: "vocal",
      what: "The exercise that was previously #1 — but now you've EARNED it. Strum Am on autopilot and sing any combination of A, C, D, E, G in any order, any rhythm, for 3 minutes straight. No target phrase, no compositional goal. Just wander through the full pentatonic. After the gradual ramp, this freedom feels completely different — you KNOW these notes.",
      setup: "Guitar. Drone on A. Metronome at 80 BPM.",
      steps: [
        { text: "Strum Am on autopilot. Turn on the drone. Close your eyes. Begin singing any pentatonic notes in any order, any rhythm. No rules. No targets. Just wander — but wander with your whole body. As each note arrives, notice where it vibrates: the chest-warmth of A, the throat-ache of C, the mobile lightness of D, the mask-openness of E, the forehead-reach of G. Let your ear and your body choose the next note together, not your brain.", why: "Open-ended exploration is Kratus Level 1 — pure creative play. With body-mapping active, the wandering has a somatic dimension: you're exploring a body geography alongside a pitch set. Each note is a place, not just a sound." },
        { text: "Sing for at least 3 minutes without stopping. When you run out of ideas, simplify — go back to two notes, or one note, and let the complexity rebuild naturally. The music never stops, even when it gets simple.", why: "Extended improvisation builds stamina and trust. The moments when you 'run out of ideas' are exactly when the interesting stuff happens — your conscious mind stops trying, and your instincts take over." },
        { text: "Embodiment check — pause and ask yourself: am I hearing each note before it arrives, AND feeling it in my body, AND singing with emotional intention? Or has autopilot kicked in and I'm just making pleasant sounds? Put your hand on your chest. As you sing, does the vibration location shift with each note? Does each phrase have an emotional intention, or are you just noodling? Full embodiment means every note is heard, felt, and chosen. If any channel has gone dark, pause. Close your eyes. Hear the NEXT note — its pitch, its body address, its emotional weight — then let it become sound.", why: "Extended improvisation triggers a well-documented autopilot trap: the voice repeats comfortable patterns while the ear, body, and emotional channels check out (Aarhus 2021 fMRI studies show reduced auditory cortex activation during 'zoned-out' improv). The embodiment check re-engages all three channels, not just the ear. When pitch, body awareness, and emotional intention are all active, you're composing in real time, not noodling." },
        { text: "Vary everything: long tones, short bursts, silence, dynamics, vowel sounds, rhythmic patterns. Apply all the tools from every phase. This is the synthesis — everything you've learned, all at once, all your choice.", why: "Synthesis is the goal of the entire level. When pitch, rhythm, dynamics, vowels, silence, and contour all vary simultaneously, you're not doing exercises anymore — you're making music." },
        { text: "In the last minute, gradually simplify. Fewer notes, longer tones, more space. End on a sustained A — home. The exploration lands where it started: one note, deeply felt.", why: "Coming home to the root after a full pentatonic journey gives closure. It also demonstrates the emotional arc you can create: departure, exploration, return. This is the shape of every great musical journey." },
        { text: "Listen back to the full recording. How does it compare to your very first explorations (Phase 1, single root note)? The difference is the ramp — you KNOW these notes now because you lived in each one.", why: "Hearing your own growth is the most powerful motivator. The pentatonic exploration should sound dramatically more musical than your early one-note exercises — because it is. You earned every note." }
      ],
      feel: "This should feel like coming home to a house you built yourself — every room is familiar because you lived in each one. The five notes are friends, not strangers. Each one has a pitch, a body address, and an emotional quality you know intimately. The freedom feels earned, not overwhelming. Always end on something that worked — a phrase that felt right, a moment where voice and chord locked. The last rep colors the whole session.",
      wrong: "If the five notes still feel random or overwhelming, go back to four notes (ss-4-1) for a while. There's no rush. The ramp works because each stage is fully internalized before the next one arrives. If three notes felt great but five feels chaotic, live in four until it's solid.",
      sarah: "Gene, compare how this feels to what it would have felt like at the start — jumping straight to five notes without the ramp. The difference is confidence. You KNOW these notes because you built them one at a time. This is what trusting the ramp sounds like.",
      drone: { root: "Am", octave: 2, texture: "pure" },
      pitchContour: true,
      metronome: 80,
      referencePitches: getPitchRange("A2", "G4"),
      recorder: true
    },

    // ─── PHASE 6: OTHER CHORD PALETTES ───

    {
      id: "ss-4-8",
      time: 8,
      title: "Major Palette — G Major",
      type: "vocal",
      what: "Apply the same palette thinking to G major. Root G (earth), major 3rd B (gold/sunshine — brighter than the minor 3rd!), 5th D (sky). The major triad has a COMPLETELY different emotional color — warm, open, bright. Your pentatonic exploration was in minor. Now feel major.",
      setup: "Guitar. Drone on G. Metronome at 80 BPM.",
      steps: [
        { text: "Strum G on autopilot. Turn on the drone (G). Sing the root G — hold it for 8 beats. This is a new home. It feels similar to A (stable, grounded) but the surrounding notes will be different colors.", why: "Establishing a new root resets your palette. You've lived in Am for the entire level — G major is a new tonal world with different emotional colors." },
        { text: "Sing the 5th (D) — hold for 8 beats. Open sky, just like E was over Am. The 5th always has this quality — spacious, stable, expansive. Same relationship, new notes.", why: "The 5th has the same character regardless of the chord — it's always the 'sky.' Recognizing this consistency across different chords builds your understanding of how chord tones work universally." },
        { text: "Sing the major 3rd (B) — hold for 8 beats. Feel the difference from C (the minor 3rd over Am). B is BRIGHT. Warm. Golden. Sunshine instead of blue. And notice where B lives in your body — does it sit in the same throat-ache location as C, or does it feel more forward, more projecting, more open? The major 3rd often resonates with more width, less compression. This is the major-minor fork — and it's a completely different emotional world, felt in a different body location.", why: "The major 3rd vs minor 3rd is the most important emotional distinction in Western music. The body-location shift between minor 3rd (compressed, aching) and major 3rd (open, projecting) gives you a somatic anchor for the distinction — you can feel major vs. minor, not just hear it." },
        { text: "Paint freely: G (earth), B (gold), D (sky). 2 minutes. Before each note, hear it in your head — even for a split second. Which color do you want to paint next? Hear the gold of B, the sky of D, the earth of G — then let your voice trace what your ear chose. Feel how the major palette has a fundamentally different character — brighter, more open, warmer.", why: "Internalizing the major palette as 'warm/golden' and the minor palette as 'blue/aching' gives you emotional language for chord colors. The 'hear it first' habit means your ear is choosing the color, not your fingers or muscle memory. This is musical literacy through feeling." },
        { text: "Palette switch audiation test: before you change from Am to G major, STOP strumming for one beat. In that beat of silence, hear the new palette's color — pre-hear the gold of B before your fingers form the G chord. Then strum and sing. Does the note that comes out match what you heard in the silence? This is pre-hearing across chord changes — the skill that makes real-time palette switching musical instead of mechanical.", why: "Pre-hearing across harmonic boundaries is a higher-order audiation skill (CLA Gray 2018). Most singers react to chord changes after they happen. Hearing the new palette BEFORE the change means you're leading with your ear, not following with your fingers. The beat of silence is the audiation window." },
        { text: "Try the full major pentatonic: G-A-B-D-E ascending, E-D-B-A-G descending. Five notes over G major. Improvise freely for 2 minutes. Record it. Compare the feeling to your Am pentatonic improvisations.", why: "The major pentatonic over G is the bright, sunny counterpart to Am pentatonic. Experiencing both gives you two complete emotional palettes — all the colors of warmth AND all the colors of melancholy." }
      ],
      feel: "The G major palette should feel like stepping from a moody evening into warm afternoon sunlight. Same framework (root, 3rd, 5th), completely different emotional temperature. Gold instead of blue.",
      wrong: "If G major and Am feel the same emotionally, spend more time on the 3rd. Hold B (major 3rd) for 16 beats, then switch to C (minor 3rd over Am). The difference is the emotional hinge — everything else is similar. Keep switching until the contrast is visceral.",
      sarah: "Gene, your playlist has both colors — the golden warmth of surf-rock and the blue melancholy of desert blues. Now you can choose which palette to sing in. G major is your sunshine sound; Am is your golden-hour sound. Both are you.",
      drone: { root: "G", octave: 2, texture: "pure" },
      pitchContour: true,
      metronome: 80,
      referencePitches: getPitchRange("G2", "D4"),
      recorder: true
    },
    {
      id: "ss-4-9",
      time: 7,
      title: "Palette Switching — Am to G",
      type: "vocal",
      what: "Alternate between Am palette (A-C-E, blue) and G palette (G-B-D, gold) every 4 bars. Feel the color shift as the chord changes. This is the foundation of singing over chord progressions — each chord gives you a new palette of colors to paint with.",
      setup: "Guitar. Metronome at 80 BPM.",
      steps: [
        { text: "Strum Am for 4 bars while singing A-C-E (blue palette). Then switch to G for 4 bars while singing G-B-D (gold palette). Repeat the cycle 4 times. Feel the emotional shift at each chord change — blue to gold, gold to blue.", why: "Palette switching is the foundation of singing over chord progressions. Each chord change brings a new set of colors — the singer's job is to hear the shift and respond with the appropriate palette." },
        { text: "Focus on the moment of the switch. As the chord changes from Am to G, three things shift simultaneously: the PITCH palette changes from blue (A-C-E) to gold (G-B-D), the BODY resonance migrates — C's throat-ache gives way to B's brighter, more forward buzz — and the EMOTIONAL temperature warms from melancholy to sunlight. Notice which note makes the biggest change: C (minor 3rd, blue, sitting in the throat) becomes B (major 3rd, gold, projecting forward). That one note shift changes everything — pitch, body, emotion all at once.", why: "The 3rd is the hinge between major and minor. Tracking the shift across all three channels — pitch, body, emotion — makes the chord change a full-spectrum event rather than just a note swap." },
        { text: "Try smooth transitions: end your Am phrase on a note that's close to a G chord tone (E resolves naturally to D, or A sits inside both chords). The smoothest chord changes connect the two palettes rather than jumping between them.", why: "Voice leading — connecting chord tones smoothly across chord changes — is what makes melody flow through progressions. Finding the connecting notes between palettes is a core songwriting skill." },
        { text: "Before each chord change, the drone gives you the anchor. From that anchor, can you PRE-HEAR the first note of the new palette? As the Am bars end, hear the gold of B (G major's 3rd) forming inside — feel the interval distance from the drone root. Then when the chord changes, sing B immediately. The drone is your compass — every interval is measured from it. Try this for 4 chord changes: pre-hear the target note in the last beat before the switch, then land on it.", why: "Pre-hearing across chord boundaries uses the drone as a stable reference point. Even as the chord changes, the drone anchor lets you FEEL the interval to your target note. This is how experienced singers navigate chord progressions — they hear the next note before the chord arrives, using the tonal center as their map." },
        { text: "Reverse the emphasis: make Am feel bright and energetic, make G feel mellow and laid-back. Same notes, different emotional delivery. Notice what changes in your body when you override the palette's default mood — singing Am with energy might push the resonance higher and more forward; singing G with melancholy might pull it deeper into the chest. You're choosing the emotional channel independently of the pitch channel. Prove that the palette is a starting point, not a prison.", why: "The palette gives you the NOTES; your delivery gives them EMOTION. The body follows the emotional choice, not just the pitch — when you choose melancholy over a bright chord, the resonance shifts accordingly. This proves that the hear-feel-choose cycle is truly independent: you can feel different things with the same notes." },
        { text: "Free improvisation: alternate Am and G in 4-bar blocks, painting freely with each palette. 2 minutes. Record it. Listen for the color shifts — do they sound like natural mood changes, or like two unrelated sections? Final 2 minutes: mix this palette switching with something from your last 2 sessions — a rhythm cell, a vowel shape, an emotional color. Random switching between skills builds stronger, more transferable musicianship than drilling one thing.", why: "Smooth palette switching is what makes songs feel like unified wholes rather than disconnected sections. When the color shifts feel natural, you're singing over chord changes — the fundamental skill of all popular music. Mixing skills from different sessions (contextual interference) improves long-term retention over blocked practice." }
      ],
      feel: "The switches should feel like natural mood shifts — like watching the sky change from blue to gold at sunset. Not abrupt, not forced, just a gentle emotional modulation. Each palette has its own warmth.",
      wrong: "If the chord changes sound like two separate songs rather than one flowing piece, focus on the transition moments. Sing a note that belongs to BOTH chords at the switch point (like the note E, which is the 5th of Am and the 6th of G — it works in both contexts).",
      sarah: "Gene, this is how songs work — each chord gives you a new palette, and the melody paints with whatever colors are available. When you can feel the shift between Am blue and G gold, you're hearing chord progressions the way songwriters hear them. That's a big deal.",
      pitchContour: true,
      metronome: 80,
      referencePitches: getPitchRange("G2", "E4"),
      recorder: true
    },

    // ─── PHASE 7: EXPRESSION & TEXTURE ───

    {
      id: "ss-4-10",
      time: 7,
      title: "Vowel Shape Exploration",
      type: "vocal",
      what: "Sing pentatonic notes while cycling through vowels: 'ooh' (intimate), 'ahh' (open), 'eee' (bright), 'oh' (warm), 'ay' (forward). Each vowel creates a different resonant space in your body. Your vowel choices will become a signature part of your vocal style.",
      setup: "Guitar. Metronome at 80 BPM. Strum Am.",
      steps: [
        { text: "Strum Am on autopilot. Before singing, hear A forming in your chest — feel the warmth gathering behind the sternum. Now shape your mouth into a small 'ooh' circle and let the note emerge. Sing pentatonic notes on 'ooh' for 1 minute. As you move between notes, track two body maps at once: the PITCH map (A in chest, C in throat, D between them, E in mask, G reaching toward the forehead) AND the VOWEL map ('ooh' concentrates resonance behind the lips and deep in the chest). Notice how 'ooh' pulls every note slightly downward in the body — even E, which normally lives in the mask, feels warmer and more contained on 'ooh.' The vibration feels private, intimate. 'Ooh' is where lullabies and quiet confessions live.", why: "'Ooh' is the most intimate vowel — it focuses your breath into a narrow stream and creates a warm, close sound. Tracking both the pitch body-map and the vowel body-map simultaneously builds a two-dimensional somatic awareness: every note-vowel combination has its own unique body address." },
        { text: "Switch to 'ahh' for 1 minute. Open your mouth wide. Feel how 'ahh' opens the throat and projects into the room — the resonance expands from a point to a sphere. The same pentatonic notes now buzz through your whole jaw, throat, and upper chest. Same pitch, completely different body experience. 'Ahh' fills a room because it fills your body first.", why: "'Ahh' is the most open vowel — it projects naturally and carries emotion. The body-location shift from 'ooh' (concentrated, private) to 'ahh' (expanded, projecting) is dramatic and worth tracking consciously." },
        { text: "Try 'eee,' 'oh,' 'ay' — 30 seconds each. 'Eee' is bright and forward, buzzing in the mask and nose bridge. 'Oh' is round and warm, sitting between 'ooh' and 'ahh' in both mouth shape and body resonance. 'Ay' is bright but open, vibrating forward in the teeth and hard palate. Each vowel has its own body address — and combining vowels with different pentatonic notes creates a matrix of resonance locations.", why: "Vowel awareness is foundational vocal technique. Professional singers choose vowels deliberately for their sonic properties. Mapping each vowel to its body resonance gives you a second dimension of somatic awareness alongside pitch." },
        { text: "Free improv: change vowels mid-phrase. Start a pentatonic phrase on 'ooh,' slide into 'ahh,' end on 'oh.' As vowels change mid-phrase, feel the resonance MIGRATE through your body — from the concentrated warmth of 'ooh' to the open expansion of 'ahh' to the round center of 'oh.' Let vowel changes add texture and emotional shift to your melody. 2 minutes.", why: "Vowel modulation is an advanced expressive technique that most singers never consciously develop. Tracking the body-resonance migration as vowels change makes the technique somatic, not just acoustic." },
        { text: "Try matching vowels to emotional intent: use 'ooh' for the quiet, mysterious pentatonic phrases and 'ahh' for the more open, emotional ones. Let the vowel SERVE the emotion. Record 2 minutes.", why: "Intentional vowel-emotion pairing is how great singers create consistent vocal identity. When vowel choice serves emotional intent, the voice sounds authentic and considered — never random." }
      ],
      feel: "Each vowel should feel like a different room — 'ooh' is a small intimate space, 'ahh' is a large open hall, 'eee' is bright and focused, 'oh' is warm and round. The melody stays the same; the rooms change.",
      wrong: "If all your vowels sound the same, you're not shaping your mouth distinctly enough. Exaggerate the shapes — make 'ooh' extremely round (like you're blowing out a candle) and 'ahh' extremely wide (like a doctor is checking your throat). The middle ground will emerge.",
      sarah: "Gene, listen to how BALTHVS and Khruangbin use vowel sounds as texture — 'ooh' and 'ahh' aren't random, they're color choices. Your vowel instincts will shape your songwriting style just as much as your note choices.",
      metronome: 80,
      referencePitches: getPitchRange("A2", "E4"),
      recorder: true
    },
    {
      id: "ss-4-11",
      time: 6,
      title: "Breath as Phrase",
      type: "vocal",
      what: "One breath = one phrase. Inhale, sing pentatonic notes for the length of your breath, stop when the air runs out. The breath shapes the phrase naturally — no counting, no planning. Your lungs become the composer.",
      setup: "Guitar. Metronome at 80 BPM. Backing track.",
      tracks: [{ name: "Deep Soul Groove 80", src: "/deep-soul-groove-80.mp3" }],
      steps: [
        { text: "Strum Am on autopilot over the backing track. Take a deep breath — and during that inhale, let your phrase begin forming inside: hear the first notes, feel where they'll start in your body, sense what emotional color they carry. Then exhale and sing pentatonic notes (A-C-D-E-G) for as long as your breath lasts — then stop. Don't gasp for more air. Just stop. Silence until your next natural inhale. The inhale is where the hear-feel-choose cycle runs; the exhale is where it becomes music.", why: "Breath-phrase coupling is how natural phrasing develops. Your lungs determine phrase length — not a metronome, not a bar count. Making the inhale the audiation and embodiment moment transforms breathing from a mechanical necessity into a creative act." },
        { text: "Try short breaths: quick inhale, hear 2-3 notes forming inside — feel their body addresses lighting up (chest? throat? mask?) — then sing them in a burst. Then deep breaths: long inhale, let a flowing 8-10 note phrase crystallize internally — feel the vibration path it will trace through your body — then sing the whole arc. Notice how breath depth changes both phrase character and body journey: short breaths stay in one body zone; deep breaths travel from chest through mask and back.", why: "Short breaths create punchy, rhythmic phrases. Deep breaths create long, flowing lines. Both are valid musical tools — and your breath is the control mechanism. Pre-hearing during the inhale transforms breathing from mechanical necessity into an audiation window." },
        { text: "Let the breath endings surprise you. Don't plan when to stop — just sing until the air runs out. As the air thins, notice how your body chose the phrase length. The ending wasn't planned by your mind; it was shaped by your body — your diaphragm, your lung capacity, your relaxation level all contributed to the phrase's arc. The natural endings create organic phrase shapes that sound effortless and human.", why: "Planned phrase endings sound calculated. Breath-shaped endings sound natural. Recognizing the body as the phrase-shaper deepens the connection between physical sensation and musical form — your instrument is literally composing through its physical limitations." },
        { text: "2-minute freestyle: breath-shaped pentatonic phrases over the backing track. Each phrase is exactly one breath long. Let the soul groove shape your note choices while your breath shapes your phrase lengths. Record it.", why: "When breath shapes your phrases, your singing sounds human and authentic. This is the phrasing style of DOPE LEMON, Angus Stone, Jack Johnson — effortless because it follows the body." },
        { text: "Listen back. The phrases should have a natural, organic quality — longer phrases that build, shorter phrases that punctuate, and silences between that let the music breathe. This is YOUR phrasing signature.", why: "Self-listening for phrasing quality teaches you to recognize natural vs. forced phrasing. The breath-shaped phrases should sound like you're talking in music, not executing a plan." }
      ],
      feel: "This should feel like sighing musically — each phrase is an exhale that happens to be pitched. No effort, no planning. Breathe in, sing out, rest. The groove carries you between phrases.",
      wrong: "If you're gasping for air or pushing past your breath to finish a phrase, you're overriding the exercise. Shorter phrases are fine — a 3-note phrase on a short breath is just as valid as a 10-note phrase on a deep breath. The breath IS the phrase.",
      sarah: "Gene, your laid-back vocal style is naturally breath-shaped — you don't belt or push. This exercise makes that instinct conscious and applies it to your full pentatonic vocabulary. Let your lungs be the composer.",
      metronome: 80,
      referencePitches: getPitchRange("A2", "E4"),
      recorder: true
    },
    {
      id: "ss-4-12",
      time: 6,
      title: "The Power of Silence",
      type: "vocal",
      what: "Strum Am for 4 bars. Sing pentatonic notes for 2 bars. Rest for 2 bars. Repeat. Then: sing 1 bar, rest 3. Then: sing a single note, rest 7 bars. Explore how silence creates anticipation and makes each note more powerful.",
      setup: "Guitar. Metronome at 80 BPM. Backing track.",
      tracks: [{ name: "Cinematic Western 80", src: "/cinematic-western-80.mp3" }],
      steps: [
        { text: "Strum Am over the backing track. Sing pentatonic phrases for 2 bars, then rest (no voice) for 2 bars. Repeat this cycle 4 times. Let the silence feel intentional, not empty. The guitar and backing track fill the space.", why: "Silence is a musical element, not an absence. Planned rests create anticipation — the listener leans in, waiting for the next sound. The space between phrases is where the music breathes." },
        { text: "Increase the silence: sing for 1 bar, rest for 3 bars. The singing becomes rare and precious. Each pentatonic phrase carries more weight because there's so much space around it.", why: "Scarcity creates value. When you sing less, each note matters more. This is how Hermanos Gutiérrez and Tinariwen build drama — not through volume, but through restraint." },
        { text: "Maximum silence: sing a single pentatonic note, then rest for 7 bars. But that single note should be the most EMBODIED note you've ever sung. You had 7 bars to hear it forming, feel where it will live in your body, choose what it will carry. When it finally arrives, let it be an event in your whole body — not just a pitch but a vibration you placed with full intention in exactly the right body location with exactly the right emotional weight. One note in 8 bars. Let the cinematic western backing track and guitar fill the rest.", why: "A single note surrounded by 7 bars of silence is a compositional statement. When that note is fully pre-heard, pre-felt, and pre-chosen, it carries the weight of all three channels compressed into one sound. This is embodiment at maximum concentration." },
        { text: "Free improv: vary your singing-to-silence ratio freely. Sometimes dense pentatonic phrases, sometimes a single note in a sea of space. But here's the reframe: those bars of silence aren't empty. During every rest, your brain should be HEARING your next phrase — its notes, its rhythm, its dynamic shape — fully formed inside your head before a single sound leaves your mouth. The silence is where composition happens. When does the music NEED your voice, and when does it need your silence? 2 minutes.", why: "Density control — choosing how much to sing — is one of the most advanced musical skills. Reframing silence as active audiation time (Aarhus 2021) transforms 'waiting' into 'composing internally.' Your inner ear builds the phrase during the rest; your voice merely delivers what's already been heard. Most beginners over-sing. Masters use the silence to pre-hear — and when they finally sing, the phrase arrives fully formed." },
        { text: "Record 2 more minutes. This time, imagine you're scoring a scene — a lone figure walking through a desert, or standing on a cliff at sunset. Your voice is the narration. When does the narrator speak, and when does the landscape speak for itself?", why: "Connecting silence to imagery makes it intentional rather than accidental. When you choose silence for dramatic effect, every note that follows gains weight and meaning." }
      ],
      feel: "The silences should feel active, not awkward. You're choosing to be quiet — the music continues in the guitar and backing track. Your absence creates a space the listener fills with anticipation. When your voice returns, it means something.",
      wrong: "If the silences feel uncomfortable and you rush to fill them, that's the instinct this exercise is training you to overcome. Sit with the discomfort. The silence IS the music. If you can't resist singing, try counting the silent bars in your head to stay disciplined.",
      sarah: "Gene, Hermanos Gutiérrez barely sing at all — their music is 90% space and 10% voice, and that cinematic western sound is BUILT on silence. The backing track gives you that exact world. Let the space do the work.",
      metronome: 80,
      referencePitches: getPitchRange("A2", "E4"),
      recorder: true,
      volumeMeter: true
    },
    {
      id: "ss-4-13",
      time: 6,
      title: "Sing-Along Absorption",
      type: "vocal",
      what: "Pick a backing track and LISTEN for 30 seconds — hear where the groove breathes, where the accents fall, where silence lives. Then hum along, matching the track's energy and phrasing patterns. No chord tones to hit, no rules — just absorb the groove through your body. Mirror neuron research shows that active listening IS motor rehearsal.",
      setup: "Guitar optional. One backing track of your choice.",
      tracks: [
        { name: "Khruangbin Style 80", src: "/khruangbin-style-80.mp3" },
        { name: "Reggae One Drop 85", src: "/reggae-one-drop-85.mp3" },
        { name: "Desert Blues 75", src: "/desert-blues-75.mp3" }
      ],
      steps: [
        { text: "Pick a backing track. Just LISTEN for 30 seconds with eyes closed. Don't play, don't hum. Map the groove in your body — where does the kick drum pulse? In your chest? Your belly? Where does the hi-hat shimmer? In your head? Your shoulders? The groove has body locations, just like notes do. Feel where the accents land physically, where the silence opens up, where the music breathes.", why: "Mirror neuron research shows that focused listening activates the same motor pathways as performing. When you deeply listen to a groove, your brain is rehearsing it — even in silence. Mapping the groove to body locations creates a somatic template for the feel." },
        { text: "Start humming along — no specific notes, no pentatonic thinking. Just match the ENERGY of the track. Your body is absorbing the groove's phrasing — not just the rhythm, but WHERE in the body the music lives. When the melody rises, feel the vibration climbing: chest (low notes) → throat → mask → forehead (high notes). When it descends, feel it settling back down. When you hear a phrase you love in the track, try to hold it internally for a moment — catch both the pitch AND its body address. Where is it gathering? Behind the sternum? The nose bridge? Hold it for a beat, then hum it back from that felt place. That tiny pause between hearing and humming is audiation in action.", why: "Humming along with a reference is how musicians have learned for millennia — before notation, before theory. Adding the body-location channel to the absorption means you're not just learning WHAT the groove plays but WHERE it lives in you physically. The echo-and-hold technique bridges absorption and embodied audiation. Tracking the vibration-rising map during absorption means the somatic anchor is active even during passive listening." },
        { text: "Now add your guitar (strum Am lightly). Keep humming along with the track. Let the track's groove shape your strum pattern AND your humming. You're a third instrument joining the band.", why: "Matching a track while playing trains entrainment — your body syncing to an external groove. This is the foundation of playing with other musicians and playing with feel." },
        { text: "Switch to a different backing track. Notice how your humming and strumming instantly change character. The reggae groove makes you sway differently than the desert blues. 2 minutes per track. Try all three.", why: "Different grooves pull different responses from you. Building the habit of listening-then-absorbing means every song you hear becomes a lesson in phrasing and feel." },
        { text: "On the third track, transition from humming to singing pentatonic notes. Let the groove you absorbed guide your note choices and phrasing. Record this final version.", why: "The transition from humming to pentatonic singing applies your absorbed groove vocabulary to your five-note palette. The groove shapes the melody — not the other way around." }
      ],
      feel: "This should feel like joining a conversation that's already happening — you're not leading, you're blending in. The track is the teacher. Your job is to absorb its phrasing, its timing, its attitude.",
      wrong: "If you're ignoring the track and doing your own thing, you're missing the exercise. The whole point is to let the track shape your response. Listen first, always. If your humming doesn't change when you switch tracks, you're not listening deeply enough.",
      sarah: "Gene, this is how you already learn music — you listen to Khruangbin and Skinshape, and their phrasing seeps into you. This exercise makes that absorption conscious and deliberate. Every listen is a lesson, every groove is a teacher. Pick the backing track that calls to you — the one your body responds to first, not the one you think you 'should' practice with.",
      metronome: 80,
      recorder: true
    },
    {
      id: "ss-4-14",
      time: 8,
      title: "Object Writing — Sensory Vocabulary",
      type: "record",
      what: "Pat Pattison's #1 daily exercise from Berklee. Pick an object — a surfboard, a bonfire, a highway at dusk. Set a timer for 7 minutes. Write (or speak into your recorder) using ALL your senses: what does it look like, sound like, smell like, taste like, feel against your skin? What does your body feel internally? Where are you in space? No editing, no judging — just sensory flow.",
      setup: "Phone recorder or notebook. No guitar needed. Timer set to 7 minutes.",
      steps: [
        { text: "Pick an object that connects to your music — a wave, a desert road, a porch at sunset, a bonfire, a vintage amplifier. Something with sensory richness. Set a 7-minute timer.", why: "Pat Pattison at Berklee assigns this daily. The objects you choose reveal your artistic world. Songwriters who do this daily build a sensory vocabulary that makes lyrics vivid instead of generic." },
        { text: "Start the timer. Speak into your recorder (or write) using ALL 7 senses: sight, sound, smell, taste, touch, organic (internal body feelings — heartbeat, breath, tension), kinesthetic (your body's position in space). Don't stop. Don't edit. Just flow.", why: "The 7-sense framework forces you past the visual default. Most people describe what they SEE. Songwriters who access all senses create lyrics that listeners FEEL. 'The salt air coating my lips' beats 'the beautiful ocean' every time." },
        { text: "When the timer goes off, stop. Read or listen back. Circle or note any phrase that surprised you — something vivid, unexpected, or emotionally charged. These surprises are song seeds.", why: "The surprises are gold. Your conscious mind writes clichés. Your subconscious, freed by the timer pressure, produces original imagery. The circled phrases become future lyrics." },
        { text: "Try it again with a different object. This time, pick something from your musical life — the feeling of singing a note that locks with the chord, the sensation of a guitar string under your fingertip, the way a reggae groove makes your body sway.", why: "Object writing about musical experiences builds the vocabulary to write ABOUT music. Your lyrics will eventually describe musical moments with the same specificity you use for surfboards and sunsets." },
        { text: "Keep both recordings. These are raw material for future songwriting — you'll draw from them in Levels 6 and beyond. The sensory vocabulary you build now powers every lyric you'll ever write.", why: "Object writing is cumulative. Each session adds to your sensory database. Songwriters who practice this daily for months find that vivid imagery flows naturally into their lyrics — it becomes automatic." }
      ],
      feel: "This should feel like stream-of-consciousness — messy, surprising, sometimes nonsensical. The mess is where the gold hides. Don't try to write 'good' — try to write FAST and SPECIFIC.",
      wrong: "If you're writing abstract emotions ('I felt happy,' 'the sunset was beautiful'), you're staying on the surface. Dig into the senses: WHAT does happy feel like in your chest? What COLOR is the sunset — not 'orange' but 'the orange of old rust on a tailgate'? Specificity is everything.",
      sarah: "Gene, this is the foundation of every great lyric you've ever loved. 'Beautiful day that you know will end' — that's sensory, specific, embodied. Object writing builds the muscle that produces lines like that. Do this daily, even for 5 minutes, and your lyrics will transform.",
      recorder: true
    },
    {
      id: "ss-4-15",
      time: 7,
      title: "Pentatonic Groove Palette",
      type: "vocal",
      what: "Bridge exercise: now that you own the full pentatonic, apply it to groove contexts. Sing pentatonic phrases over two contrasting backing tracks — notice how the same five notes feel completely different depending on the groove underneath. The palette is fixed; the feel transforms everything.",
      setup: "Guitar. Metronome at 80 BPM. Backing tracks.",
      tracks: [{ name: "Reggae One Drop 85", src: "/reggae-one-drop-85.mp3" }, { name: "Desert Blues 75", src: "/desert-blues-75.mp3" }],
      steps: [
        { text: "Play the Reggae One Drop track. Strum Am on autopilot. Sing pentatonic phrases (A-C-D-E-G) that fit the reggae pocket — bouncy, offbeat, laid-back. Notice how the reggae groove changes WHERE the notes live in your body: does the bounce make the resonance more mobile, more buoyant? The notes might feel lighter, higher in the chest, almost floating on the offbeat. Let the groove shape your note choices, your phrasing, and your physical sensation. 2 minutes.", why: "The reggae groove pulls specific rhythmic responses from you. Your pentatonic notes will land differently — more offbeat, more space, more bounce. Tracking the body-location shift that the groove creates adds a somatic dimension to genre awareness." },
        { text: "Switch to Desert Blues. Same five notes. Completely different energy — sparse, hypnotic, meditative. Does the desert blues make the notes settle deeper into the chest, more grounded and still? Let longer spaces between phrases. Hold notes longer. Feel how the same A that bounced in reggae now sits heavy and ancient over the desert groove. Let the groove slow your phrasing down. 2 minutes.", why: "Desert blues is the opposite of reggae's bounce — it's wide, open, and patient. The same pentatonic notes feel ancient and spacious instead of bouncy and bright. The body responds differently to each genre — resonance location shifts with the feel." },
        { text: "Switch back and forth: 1 minute reggae, 1 minute desert blues. Feel how your voice adapts to each groove. Same notes, same scale, same you — different music entirely.", why: "Rapid switching proves that your five notes are a versatile palette. The GROOVE determines the genre, not the notes. This is a key insight for songwriting — change the feel and you change the song." },
        { text: "Mid-exercise autopilot check: are you still hearing each phrase before it comes out, or has the groove lulled you into cruise control? Test yourself — stop singing for 4 bars, hear a specific phrase in your head (note choices AND rhythm), then sing exactly that phrase. If what comes out matches what you heard inside, your audiation is engaged. If something different comes out, the groove is driving and your ear is asleep.", why: "Groove contexts are the most dangerous for autopilot singing — the feel is so good that your voice can coast on muscle memory while your inner ear checks out. The 4-bar silence test forces a reset: composing internally, then executing. This is the difference between noodling and improvising." },
        { text: "Pick the groove that felt more natural to you. Spend 2 more minutes in it, letting your pentatonic improvisation deepen. Record it.", why: "Your natural groove preference reveals something about your artistic identity. The genre you feel most at home in is a starting point, not a destination." },
        { text: "Listen back. Your pentatonic improvisation should sound genre-appropriate — the reggae version should bounce, the desert blues version should breathe. If both sound the same, the groove hasn't gotten into your body yet.", why: "Genre-appropriate phrasing means the groove has shaped your musical instincts. When the same five notes sound like two different genres, you've internalized feel — not just notes." }
      ],
      feel: "This should feel like the same five colors painted on two different canvases — one vibrant and bouncy, one wide and meditative. The notes are tools; the groove is the artist directing your hand.",
      wrong: "If your reggae and desert blues versions sound identical, you're ignoring the groove. Let the backing track lead — match its energy, its density, its rhythmic placement. The groove tells you HOW to sing your notes.",
      sarah: "Gene, this is exactly the skill that Khruangbin has mastered — they use the same pentatonic vocabulary but shift effortlessly between Thai funk, dub reggae, and desert blues. The notes don't change; the feel does. You're building that versatility.",
      metronome: 80,
      referencePitches: getPitchRange("A2", "G4"),
      recorder: true
    },

    // ─── PHASE 8: RHYTHM & FEEL — APPLIED TO PENTATONIC ───

    {
      id: "ss-4-16",
      time: 8,
      title: "Groove Lock",
      type: "guitar",
      what: "Strum along with a backing track and LOCK into the groove. Don't just play in time — feel where the drums, bass, and guitar create a unified pulse. When you're locked in, your strum becomes part of the recording. This is 'entrainment' — your body syncing to external rhythm. Now that you own the pentatonic, you can add vocal colors while staying locked.",
      tracks: [{ name: "Groove Beat 90", src: "/groove-beat-90.mp3" }, { name: "Dub Reggae 85", src: "/dub-reggae-85.mp3" }, { name: "Drums Only — Reggae 85", src: "/drums-reggae-85.mp3" }],
      steps: [
        { text: "Play the Groove Beat track. Just LISTEN for 30 seconds with eyes closed. Feel where the groove lives in your body — the kick in your chest, the snare in your head-nod, the hi-hat in your breathing. This isn't wasted time — it's neural entrainment, priming your motor system through focused listening. When your body is moving with the groove, THEN pick up your guitar.", why: "30 seconds of focused listening primes the motor system through neural entrainment. Identifying the drum elements in your body lets you sync your strum to physical sensation, not just auditory timing. The kick is beat 1, the snare is beat 2 and 4." },
        { text: "Start strumming along — simple downstrokes first. Match your strum to the hi-hat rhythm. When your strum disappears into the track, you're locked.", why: "The 'disappearing strum' test: if you can't hear your guitar as separate from the recording, your timing is perfect." },
        { text: "Switch to the Dub Reggae track. Change your strum to offbeat chops. Lock into the reggae pocket — your chops should sit between the kicks.", why: "Different genres have different pockets. Locking into reggae after a straight groove proves your rhythm is adaptable, not rigid." },
        { text: "Try this: close your eyes and feel where the groove 'wants' your strum. Let the backing track pull your hand — and pull your whole body. This is embodiment from the outside in: the groove enters through your ears, settles into your chest and hips, and your hand follows your body's sway rather than your brain's counting. Don't think — just feel.", why: "Entrainment is subconscious. When you stop thinking about timing and let the groove carry you, that's real musicianship. The body mediates between the external groove and the hand — the groove lives in your torso before it reaches your fingers." }
      ],
      feel: "When you're locked into a groove, it feels effortless — like the music is playing you. Your body moves naturally. Time disappears. This is the 'flow state' of rhythm.",
      wrong: "If your strum sounds separate from the track (you can clearly hear two rhythmic sources), you're not locked. Adjust micro-timing: try playing slightly behind the beat (laid-back) or right on top.",
      sarah: "Gene, groove lock is the difference between a metronome player and a musician. Your favorite artists — Khruangbin, Skinshape — have supernatural groove. This exercise builds that feel.",
      metronome: 90,
      recorder: true
    },
    {
      id: "ss-4-17",
      time: 8,
      title: "Feel Shifts",
      type: "guitar",
      what: "Play the SAME chord progression (Am-C-G-Em) in 4 different genre feels: reggae offbeat, surf jangle, soul strum, and desert blues. Same chords, totally different vibes. Your right hand creates the genre — not your left. Now that you have the full pentatonic, notice how the SAME notes feel completely different depending on the strum pattern underneath. This is constraint-led approach (CLA): same task, different movement solutions.",
      steps: [
        { text: "Reggae: muted offbeat chops at 85 BPM. Am-C-G-Em. Choppy, bouncy, laid-back. Feel where the reggae lives in your body — the bounce concentrates in your shoulders and upper chest, a buoyant, mobile sensation. Your head might nod. Your weight feels light. 2 minutes.", why: "The reggae chop emphasizes the 'and' of each beat. It creates space — the silence between chops is as important as the sound. Each genre feel has a distinct body signature that goes beyond the strum pattern." },
        { text: "Surf jangle: continuous 8th-note down-up at 100 BPM. Same chords. Shimmering, continuous, bright. The jangle feel floats — it lives in the mask and forehead, a shimmering sensation that spreads across your face and the top of your chest. Your body might sway side-to-side. 2 minutes.", why: "Jangle is the opposite of reggae — constant motion instead of space. Same chords, completely different energy and body location." },
        { text: "Soul strum: relaxed 16th-note pattern at 80 BPM with ghost strums (light touches between real strums). Same chords. Warm, groovy. Soul lives deep in the chest and belly — warm, heavy, grounded. Your body settles into the chair, weight drops low. 2 minutes.", why: "Soul strum is about pocket — playing slightly behind the beat with ghost notes that add texture without volume. The warmth sits low in the body, a deep center-of-gravity feeling." },
        { text: "Desert blues: sparse, thumb-heavy downstrokes at 75 BPM with long spaces between strums. Same chords. Hypnotic, minimal. Desert blues feels deep and still — the resonance sinks below the chest into the belly, the spine. Your body becomes quiet, almost meditative. Space surrounds each strum like silence surrounds a single figure in a vast landscape. 2 minutes.", why: "Desert blues is the most sparse feel — space is the instrument. Tinariwen, Ali Farka Touré. Less is more. The body goes still and the resonance drops to its lowest, most centered location." },
        { text: "Your pick: which feel suits you best? Spend 3 more minutes in that feel. That's your 'home groove' for now.", why: "Identifying your home groove is an act of artistic identity. It tells you what genre your songs want to live in." }
      ],
      feel: "Each feel shift should feel like changing clothes — same body, different outfit. The chords stay familiar; only the energy and timing transform. One of these will feel like HOME.",
      wrong: "If all four feels sound the same, your right hand isn't changing enough. Reggae should sound nothing like jangle. Record yourself and compare.",
      sarah: "Gene, your playlists tell me reggae and surf are your home feels. But trying soul and desert blues might surprise you — Khruangbin lives in that soul-desert overlap.",
      tracks: [{ name: "Deep Soul Groove 80", src: "/deep-soul-groove-80.mp3" }, { name: "Desert Blues 75", src: "/desert-blues-75.mp3" }, { name: "Ska Upbeat 95", src: "/ska-upbeat-95.mp3" }, { name: "Reggae Rock 100", src: "/reggae-rock-100.mp3" }, { name: "Drums Only — Surf 120", src: "/drums-surf-120.mp3" }],
      metronome: 85,
      recorder: true
    },
    {
      id: "ss-4-18",
      time: 6,
      title: "Syncopation",
      type: "vocal",
      what: "Sing notes BETWEEN the guitar strums — on the 'ands' instead of the beats. This is syncopation: the secret ingredient that makes vocal melodies feel alive instead of robotic. Now that you own the full pentatonic, apply syncopation to your five-note vocabulary — the rhythmic displacement makes every note choice more interesting. Based on Stoloff's approach: rhythmic displacement before melodic complexity.",
      steps: [
        { text: "Strum Am at 80 BPM, simple downstrokes on beats 1-2-3-4. Before you sing, hear A gathering in your chest — feel the warmth behind the sternum forming before it becomes sound. Now sing A — but ONLY on the 'and' after beat 1. Strum... sing... strum... rest... strum... rest... strum... rest. Even with syncopation, the body address stays constant: A lives in the chest whether it lands on the beat or between beats.", why: "Singing between strums is the opposite of what your brain wants to do. It wants to sync voice and hand. Separating them is the key to interesting rhythm. Anchoring the note in its body address before syncopating it ensures the audiation-somatic connection survives the rhythmic displacement." },
        { text: "Now sing on the 'and' of beats 1 AND 3. Two syncopated notes per bar. The voice lands between strums. Notice how singing on the 'and' creates a physical tension — your body wants to sync with the guitar, but you're deliberately displacing. Feel that tension in your chest and shoulders: the strum pulls one way, your voice floats the other. That tension IS syncopation, felt in the body.", why: "Two offbeat notes per bar creates the reggae vocal feel. The physical sensation of displacement — body pulled between two rhythmic magnets — is syncopation as a somatic experience, not just a rhythmic concept." },
        { text: "Try singing on all four 'ands' — every note between the strums. Your voice fills the gaps. This is the most syncopated pattern possible.", why: "Full offbeat singing creates the classic ska/reggae vocal style. It also appears in surf-pop and psychedelic rock." },
        { text: "Mix it up: sing some notes ON the beat and some BETWEEN. Create your own rhythmic pattern. Feel the difference in your body: on-beat notes feel grounded, aligned, at rest — voice and guitar vibrate together. Off-beat notes feel suspended, floating, alive with tension. The interplay between these two body-states IS groove. Record it.", why: "Mixing on-beat and off-beat creates the most musical vocal rhythms. Every great melody does this. The somatic contrast between grounded (on-beat) and suspended (off-beat) is the physical foundation of groove." }
      ],
      feel: "Syncopation should feel groovy — like your voice is dancing between the guitar beats. When it clicks, you'll feel a swing that doesn't exist when voice and guitar land together.",
      wrong: "If all your notes land on the beat with the strum, that's singing in unison with the guitar — not wrong, but not syncopated. Practice placing notes deliberately between strums.",
      sarah: "Gene, syncopation is what makes DOPE LEMON and Skinshape vocals feel so cool. They're singing between the guitar, not on top of it. This exercise teaches that feel.",
      tracks: [{ name: "Drums Only — Reggae 85", src: "/drums-reggae-85.mp3" }],
      metronome: 80,
      referencePitches: getPitchRange("A3", "A3"),
      recorder: true
    },
    {
      id: "ss-4-19",
      time: 6,
      title: "Body Percussion Layering",
      type: "rhythm",
      what: "Four-layer body percussion: foot stomp (beats 1 and 3), knee pat (beats 2 and 4), clap (offbeats), and voice counting subdivisions. Build layers one at a time. This is advanced Dalcroze: 4 independent rhythmic streams from one body — the physical architecture of singing while playing.",
      setup: "Seated or standing. Metronome at 85 BPM. No instrument.",
      steps: [
        { text: "Layer 1: stomp your foot on beats 1 and 3. Just the foot. Lock it to the metronome until it's automatic — at least 30 seconds of perfect time.", why: "The foot is the deepest body rhythm. In Dalcroze training, the feet always come first because they connect to your body's center of gravity." },
        { text: "Layer 2: add knee pats on beats 2 and 4. Stomp-pat-stomp-pat. Two layers running simultaneously. Keep both locked to the metronome.", why: "Feet on 1-3 and hands on 2-4 creates the complete basic groove. This is the body percussion equivalent of a kick-snare pattern." },
        { text: "Layer 3: add claps on the offbeats (the 'ands'). Stomp... clap... pat... clap... stomp... clap... pat... clap. Three simultaneous rhythmic streams.", why: "Offbeat claps add the hi-hat layer. Three independent body rhythms running simultaneously is a serious coordination challenge — and exactly what singing over guitar demands." },
        { text: "Layer 4: add your voice counting subdivisions — '1-e-and-a, 2-e-and-a, 3-e-and-a, 4-e-and-a' — while maintaining all three body layers. As you count, notice where the voice sits in your body: counting naturally lives in the throat and chest, a mid-register hum. Feel that specific location — it's the same throat-to-chest zone where C and D live on your pitch map. Your body is now running four independent rhythmic streams. This IS embodied rhythm — not rhythm in your head, but rhythm distributed across your entire physical instrument: feet, hands, voice, all speaking different rhythmic languages simultaneously.", why: "Four independent rhythmic outputs is the maximum most people can manage. Connecting the voice layer to its body address — even during a rhythmic exercise — keeps the somatic awareness channel active. When you eventually replace counting with pentatonic singing, the body-address habit will already be in place." },
        { text: "If Layer 4 falls apart, drop back to 3 layers and build up again. The goal is smooth, relaxed coordination — not tense concentration.", why: "Motor learning research: if you're gritting your teeth, the coordination isn't learned yet. It should feel easy and groovy when it's truly internalized." }
      ],
      feel: "When all four layers lock in, it should feel like you ARE a drum kit — each limb and your voice operating independently but creating one unified groove.",
      wrong: "If adding a new layer causes the previous layers to falter, the earlier layers aren't automatic yet. Spend more time on fewer layers before stacking.",
      sarah: "Gene, this is the exercise that makes everything else easier. Once your body can run 4 independent rhythm streams, singing over guitar strum patterns will feel like a vacation.",
      tracks: [{ name: "Drums Only — Afrobeat 110", src: "/drums-afrobeat-110.mp3" }],
      metronome: 85
    },

    // ─── CAPSTONE ───

    {
      id: "ss-4-20",
      time: 7,
      title: "Whisper to Full Voice",
      type: "vocal",
      what: "Dynamic range exploration with pentatonic notes. Move from barely audible whisper to full chest voice and back — with all five pentatonic notes available. Dynamics in isolation: same chord, same scale, just volume as a creative variable.",
      setup: "Guitar. Metronome at 80 BPM. Strum Am softly.",
      steps: [
        { text: "Strum Am very softly. Sing pentatonic notes in a near-whisper — your voice should barely rise above the guitar. Whisper-singing lives in the throat and mouth — feel how the vibration barely reaches the chest. It's contained, private, intimate — this is your most personal body location, your DOPE LEMON register. Hold notes, drift between pitches, keep everything quiet and close.", why: "Singing quietly requires more breath control than singing loudly. It also creates intimacy — the listener leans in. At whisper volume, the resonance lives in the smallest, most contained body space." },
        { text: "Gradually increase volume over 8 bars until you're singing pentatonic phrases at full chest voice. As volume rises, feel the vibration traveling: throat → chest → ribs → whole torso. You're not just getting louder — you're waking up more of your body. The strum should get louder too — guitar and voice grow together. By full voice, your entire torso is a resonating chamber.", why: "A volume crescendo is the simplest form of musical drama. Tracking the resonance expansion from throat to full body makes the crescendo a somatic journey, not just a volume knob. You're literally inhabiting more of your physical instrument as intensity builds." },
        { text: "Now reverse: start at full voice and gradually fade to a whisper over 8 bars. Pulling back requires more control than pushing forward. Let the pentatonic phrases simplify as the volume drops — fewer notes, more space.", why: "Decrescendo is harder because your body wants to stay at the louder, easier volume. Control over the fade is what separates amateurs from artists. The fade creates tenderness and intimacy." },
        { text: "Free improv: move through your dynamic range unpredictably while singing pentatonic phrases. Whisper for 4 bars, then suddenly full voice for 2 bars, then back to medium. Surprise yourself. 2 minutes.", why: "When dynamics become a variable you control consciously, your improvisation gains a third dimension beyond pitch and rhythm. Unpredictable dynamics keep the listener engaged and the music alive." },
        { text: "Body scan as you crescendo: where does the vibration live at a whisper? (throat, maybe lips) Where does it move as you get louder? (chest, then ribcage, then the whole torso resonates) Notice the shift — at whisper volume the sound lives in your head; at full voice it drops into your body. This awareness is the seed of the body-scan singing you'll develop in Level 5.", why: "Somatic awareness of resonance shift across dynamics is a precursor to full kinesthetic audiation (Gordon Stage 6). Noticing WHERE vibration lives at each volume trains you to monitor your instrument from the inside — not just by ear, but by feel. Level 5's body awareness capstone builds directly on this." },
        { text: "Final pass: pair dynamics with pentatonic range. Low notes (A, C) sung quietly. High notes (E, G) sung louder. Then reverse: low notes loud, high notes whispered. Feel how dynamic pairing with pitch creates different emotional landscapes. Record it.", why: "Pairing dynamics with pitch range is a compositional technique. 'High = loud' is the natural instinct. 'High = soft' is the unexpected choice that creates surprise and beauty. Both are tools in your kit." }
      ],
      feel: "The whisper should feel private and close — singing for yourself. The full voice should feel open and projecting — singing for the room. The transitions should feel like sunrise and sunset — gradual, natural, inevitable.",
      wrong: "If you're stuck at one volume the whole time, you're ignoring the most powerful expressive tool you have. Push the extremes — whisper so quietly you can barely hear yourself, then open up to fill the room. The range between those extremes is your dynamic palette.",
      sarah: "Gene, your porch register naturally lives in the quieter range — that's your sweet spot. But even DOPE LEMON has dynamic peaks, and Allah-Las build from whisper to wall of sound. This exercise builds the full range around your natural center, with your full pentatonic vocabulary underneath.",
      metronome: 80,
      referencePitches: getPitchRange("A2", "E4"),
      volumeMeter: true,
      volumeContour: true,
      recorder: true
,
      levelUp: "Can walk stepwise through 4 notes, improvise freely across the full Am pentatonic, hold musical conversations at every note stage, switch between minor and major palettes, lock into backing track grooves, shift between 4 genre feels on the same progression, sing syncopated rhythms between beats, layer 4 independent body percussion streams, use silence and dynamics as expressive tools, absorb grooves through listening, audiate pentatonic phrases before singing them, and build sensory vocabulary through object writing — all while the guitar strum stays on autopilot."
    },

    // ─── AUDIATION BRIDGE (L3 → L5) ───

    {
      id: "ss-4-23",
      time: 7,
      title: "Scaffolded Audiation — Building the Inner Palette",
      type: "vocal",
      what: "You can't audiate what you've never heard. This exercise teaches you HOW to internalize notes using a scaffolding sequence: anchor (drone) → play the note externally → listen/absorb → mute → hold internally → re-sing → check. Every step is grounded in something you've already heard. You're not pulling notes from thin air — you're catching echoes and extending them.",
      setup: "Guitar. Drone on A. Pitch detector on. Metronome at 70 BPM (extra slow — this is deep internal work).",
      steps: [
        { text: "The Echo Method: play A on your guitar — a single, clear note. Listen for 3 full seconds. Just absorb it. Now mute the string. The echo lingers in your ear — hold it. Don't let it fade. Within 3 seconds of muting, re-sing A. Check with the pitch detector. This is the easiest audiation possible — you're catching the echo while it's still ringing in your head. Try it 3 times.", why: "The echo method is the foundation of all audiation scaffolding. Gordon's discrimination learning says external hearing MUST precede internal hearing. By catching the echo within 3 seconds, you're working with the brain's echoic memory — the automatic sensory trace that persists for 3-4 seconds after a sound stops. You're not 'creating' the pitch from nothing — you're HOLDING what's already there." },
        { text: "Extending the Echo: same note (A), same process — play, listen, mute. But now wait 5 seconds before re-singing. The echo fades, but your brain must SUSTAIN it actively. It takes effort now. Try it. Then extend to 8 seconds. By 8 seconds, echoic memory has faded — you're sustaining A through active audiation, not passive echo. That's the shift.", why: "Echoic memory fades at roughly 3-4 seconds. Beyond that, you're no longer catching an echo — you're actively maintaining a pitch representation in working memory. This is the transition from passive hearing to active audiation. Extending the delay trains your brain to sustain notes internally for longer, which is the prerequisite for hearing phrases before singing them." },
        { text: "The Anchor Method: the drone is playing A (your anchor — it's always there). Now play C on your guitar. Listen for 3 seconds — hear C against the drone. Feel the interval: root to minor 3rd, that blue ache. Mute the guitar. The drone is STILL playing A, and you're holding C internally. The drone gives you the harmonic context to FEEL the interval, even after C is muted. Re-sing C while the drone plays. Check. The interval (root to minor 3rd) is what you're hearing, not just an isolated pitch.", why: "The anchor method is more powerful than the echo method because it gives you a REFERENCE. Isolated pitch memory is hard — but interval memory against a drone is much easier because your brain encodes the RELATIONSHIP, not just the frequency. This is why the drone is always the anchor: it turns absolute pitch memory (hard) into relative interval memory (natural)." },
        { text: "Building the palette one note at a time: drone on A. Play each pentatonic note one at a time — A, C, D, E, G. For EACH note: play it on guitar, absorb it for 3 seconds against the drone, mute the guitar, hold the note internally for 3 seconds, re-sing it, check with the pitch detector. As you internalize each note, don't just hold the PITCH — hold the full experience: its body address, its emotional quality, its relationship to the drone. A = chest/home/grounding — the warm buzz behind your sternum, the feeling of arrival. C = throat/ache/yearning — the minor 3rd sitting between chest and mask, the emotional center. D = between chest and throat/restless/moving — lighter than A, wanting to go somewhere. E = mask/open/aspiring — the vibration climbing into your facial bones, spacious and bright. G = forehead/reaching/peak — the lightest vibration, the highest emotional reach. Each note is a complete sensory-emotional package, not just a frequency. Take your time — this is one full pass through your palette.", why: "This systematic pass maps each note as a unified experience: pitch + body location + emotional quality. By grounding each note in THREE anchors — the drone (sonic distance from home), the body (physical location), and the emotional character (what it expresses) — you're building an internal palette with triple redundancy. Zamorano 2025 showed body awareness predicts pitch accuracy (R²=0.41). Adding the emotional channel means you can reach for a note by its feeling ('I want yearning') as easily as by its pitch or its body address. This is how master singers navigate — by emotional intention, with pitch and body following automatically." },
        { text: "Interval chains: drone on A. Play C on guitar, absorb, mute, hold C internally. Now — WITHOUT playing anything — try to hear D. You know D is one step above the C you just internalized. Feel the interval from C to D (a whole step up). Sing D. Check. You built D from a note you already absorbed, not from nothing. Now from D, hear E (another whole step). Sing E. Check. Each new note is reached by interval from the last — a chain of known distances.", why: "Interval chaining teaches you to BUILD notes from notes you've already internalized. Instead of hearing each note as an isolated event, you're constructing a chain: each new note is a known distance from the previous one. This is how melodic audiation actually works — your inner ear moves by intervals, not by absolute pitches. The chain makes each new note predictable because you already know the distance." },
        { text: "The full chain from anchor: drone on A (your anchor). Without playing anything on guitar, try to hear the pentatonic ascending: A (the drone gives you this one for free — feel it in the chest)... then C (feel the minor 3rd distance from the drone, the vibration shifting to the throat)... then D (one step up from C, lighter, more mobile)... then E (the 5th, opening into the mask)... then G (the reach, climbing to the forehead). As you hear each note internally, feel it arriving at its body address before you sing it. Sing each note from that felt place. Check each one. The drone is your pitch compass, the body map is your physical compass, and together they give you a complete navigation system.", why: "This is the synthesis: hearing the full pentatonic from anchor + intervals + body addresses, with no external reference except the drone. Each note is reached by a known interval AND confirmed by a known body location — two independent verification channels. This is audiation with somatic redundancy, the most reliable way to navigate your palette internally." }
      ],
      feel: "This should feel methodical and grounding — each note earned by hearing it first, then holding it. The drone is your constant companion, your compass. Nothing is pulled from thin air. Every audiated note is built from something you've already heard: an echo, an anchor, a known interval. That's the scaffolding — and each note you absorb adds resolution to your prediction engine. Your brain's model of music is being built one note at a time.",
      wrong: "If you're trying to hear notes without any reference — no echo, no drone, no interval chain — you're skipping the scaffolding. At this level, ALWAYS start from something external. The echo method starts from a played note. The anchor method starts from the drone. The chain method starts from a note you've already absorbed. No reference = no scaffolding = frustration.",
      sarah: "Gene, this is the exercise that answers your question: 'How do I audiate if I don't hear it first?' The answer: you DON'T audiate from nothing. You audiate from echoes, from anchors, from known intervals. The drone gives you A for free. Every other note is a known distance from A. Your inner palette is a MAP, not a guess. This exercise teaches you to read that map.",
      drone: { root: "Am", octave: 2, texture: "pure" },
      referencePitches: getPitchRange("A2", "G4"),
      pitchContour: true,
      metronome: 70,
      recorder: true
    },
    {
      id: "ss-4-21",
      time: 6,
      title: "Pentatonic Audiation — Hear Three, Then Four",
      type: "vocal",
      what: "You learned to hear A and E silently in Level 3 (ss-3-8). Two notes, two colors on your inner canvas. Now expand that canvas: hear THREE pentatonic notes internally (A, C, D — earth, blue, bridge), then four, then all five. The constraint: hear the phrase in your head for a full bar before singing it. Your inner ear paints the phrase; your voice traces what's already been composed inside.",
      setup: "Guitar on autopilot (Am). Drone on A. Metronome at 75 BPM (slow — audiation needs time).",
      steps: [
        { text: "Warm up your inner ear: hear A silently for 4 beats, then sing it. Hear E silently for 4 beats, then sing it. This is ss-3-8 territory — you already know how to do this with two notes. Confirm the skill is still there.", why: "Revisiting the two-note audiation from Level 3 re-establishes the neural pathway before expanding it. If two notes feel easy, your inner ear is warmed up and ready for more colors." },
        { text: "Add C — the blue note. Hear C silently against the drone for 4 beats. Really HEAR it — feel its ache, its minor-3rd pull. Then sing it. Did it match? Now you have three colors on your inner canvas: earth (A), blue (C), bridge (D). Cycle through all three: silent A, sing A, silent C, sing C, silent D, sing D.", why: "Three-note audiation is qualitatively harder than two — your inner ear must distinguish between three colors instead of toggling between two. The drone provides the harmonic context that makes each note's character vivid even in silence." },
        { text: "Three-note phrase audiation: hear a short phrase using A, C, and D — maybe A-C-D or D-C-A — in your head for a full bar (4 beats). Don't just hear the pitches — feel the phrase as a body journey: A starts in the chest, C shifts to the throat, D lifts between them. And sense the phrase's emotional arc: grounding → ache → restlessness. Hold the whole phrase internally — pitch, body path, emotional contour — then sing it in the next bar. How close was it? Try 4 times.", why: "Hearing a SEQUENCE internally is the leap from single-note audiation to melodic audiation (Gordon Stage 6). Adding body-path and emotional-arc tracking makes the internal phrase vivid and three-dimensional — easier to hold because it has more sensory anchors." },
        { text: "Expand to four notes: add E back in. Now hear phrases using A, C, D, E — the same four notes from Phase 4. Hear a 3-4 note phrase silently for one bar, then sing it in the next bar. The extra note makes your inner canvas richer but harder to hold. 2 minutes.", why: "Four-note audiation bridges the gap between the two-note work in Level 3 and the full pentatonic. Each added note increases the combinatorial space your inner ear must navigate — more possible phrases, more colors to pre-hear." },
        { text: "Full pentatonic audiation: all five notes (A, C, D, E, G) available on your inner canvas. Hear a phrase — any length, any rhythm — for a full bar of silence. As it forms, feel the body path it traces (chest to mask to forehead?) and the emotional arc it carries (settling to yearning to reaching?). Then sing it — letting pitch, body, and emotion arrive together. The goal isn't perfection; it's the ATTEMPT to hear-feel-choose before singing. Even a rough match means your audiation is working. 2 minutes. Record it.", why: "Five-note audiation is the bridge to Level 5's full-scale audiation. Adding body-path and emotional tracking to the audiation makes the inner phrase more vivid and holdable — three channels of internal representation instead of one." },
        { text: "Cooldown: one last phrase. Hear it in your head — take your time, let it form fully. Feel its contour, its rhythm, its emotional weight. When it's vivid and complete inside, sing it out. That phrase was composed by your inner ear. That's audiation.", why: "Ending with a single, well-audiated phrase reinforces the quality over quantity principle. One phrase that was truly heard internally before singing is worth more than ten phrases that were 'sort of' pre-heard." }
      ],
      feel: "The silent bars should feel FULL, not empty — your brain is painting with sound that only you can hear. Five-note predictions mean your model is expanding — more colors, more combinations, more resolution. When the singing bar arrives, it should feel like tracing a line you've already drawn. The less gap between what you heard inside and what comes out, the sharper your prediction model has become.",
      wrong: "If you're singing without hearing the phrase first — if your voice is just 'going' without a plan — you've skipped the audiation step. Slow down. The silent bar is the exercise. The singing bar is just the check. If you can't hear a full phrase, start with a single note (go back to the warm-up) and build.",
      sarah: "Gene, this is the skill that separates the musicians who 'find' melodies from the ones who 'hear' them first. Mark Speer hears the lick before his fingers play it. You're building that same inner ear — starting with three colors and expanding to five. The contemplative pace suits you perfectly. Let the silence be where the music happens.",
      drone: { root: "Am", octave: 2, texture: "pure" },
      referencePitches: getPitchRange("A2", "G4"),
      pitchContour: true,
      metronome: 75,
      recorder: true
    },
    {
      id: "ss-4-22",
      time: 6,
      title: "Audiated Conversation — Hear It, Then Sing It",
      type: "vocal",
      what: "Call-and-response with a twist: during the 'silence' bars, you're not resting — you're COMPOSING your response internally. Guitar calls in bars 1-2, then 2 bars of silence where you hear your pentatonic response in your head, then you sing that pre-heard response in bars 5-6. The silence IS the audiation. Those 2 bars of rest aren't empty — your brain is composing the response.",
      setup: "Guitar. Drone on A. Metronome at 75 BPM. Backing track optional.",
      tracks: [{ name: "Desert Blues 75", src: "/desert-blues-75.mp3" }],
      steps: [
        { text: "Start simple — back to two notes, just like Level 3. Play a 2-note guitar call using A and E (bars 1-2). Then 2 bars of silence: hear your voice response (also just A and E) forming in your head. Then sing your pre-heard response (bars 5-6). Did what came out match what you heard in the silence? The 2-bar gap between call and response is your audiation window.", why: "Starting with two-note responses connects directly to ss-3-8's audiation work. The call-and-response format gives the audiation a PURPOSE — you're not just hearing notes in a vacuum, you're composing a reply. Purpose makes audiation stick." },
        { text: "Expand to three-note responses (A, C, D). Guitar calls with 2-3 notes, 2 bars of silent audiation where you hear your response forming. In those silent bars, let the response become a full-body event: hear the pitches, feel where they'll resonate, sense what they'll express. The responses should RELATE to the call — answer its contour, complement its rhythm, complete its thought. But the response must be heard, felt, and chosen internally before it's sung.", why: "Three-note responses increase the audiation load while the conversational context keeps it musical. Adding body and emotion channels to the silent audiation makes the internal phrase more vivid and the sung response more intentional." },
        { text: "Full pentatonic responses. Guitar calls use all five Am pentatonic notes. In the 2 silent bars, hear a pentatonic response — its notes, its rhythm, its body path, its emotional weight. The silence isn't empty; it's the most active part — your inner ear composing, your body preparing, your emotional intention forming. Then sing exactly what you heard-felt-chose. It's okay if the sung version isn't perfect — the goal is the ATTEMPT to pre-hear with all channels. 2 minutes.", why: "Full pentatonic audiated conversation is the synthesis of every audiation skill in L3 and L4. When all three channels — pitch, body, emotion — are active during the silent bars, the sung phrase arrives with the conviction of something fully composed, not merely imagined." },
        { text: "Variation: make the guitar call more complex (longer phrases, rhythmic variety) and the voice response simpler (2-3 notes). The constraint: you can only sing notes you truly heard in the silence. If you didn't hear it, don't sing it. Fewer, well-audiated notes beat many un-heard ones.", why: "Quality over quantity in audiation prevents the habit of 'faking it' — singing something plausible without truly pre-hearing it. The constraint 'only sing what you heard' trains honesty with your inner ear. CLA Gray 2018 calls this 'audiation integrity.'" },
        { text: "Free audiated conversation: alternate guitar calls and audiated voice responses at whatever pace feels natural. Sometimes the audiation silence is 1 bar, sometimes 4. Let the phrases breathe. The only rule: every sung note was heard internally first. Record 2 minutes.", why: "Flexible timing allows the audiation to develop at its own pace. Some phrases form instantly in the inner ear; others need longer to crystallize. Giving yourself permission to take more audiation time when needed builds a sustainable practice habit." },
        { text: "Listen back to the recording. Can you hear the difference between responses that were truly pre-heard and ones where your voice just 'went'? The pre-heard phrases tend to be more coherent, more intentional, more musical. That coherence is the sound of audiation working.", why: "Self-listening for audiation quality trains you to recognize the difference between composed and reactive singing. Over time, the pre-heard quality becomes your default — every phrase passes through the inner ear before leaving the mouth." }
      ],
      feel: "The 2 bars of silence should feel like the most active part of the exercise — your brain is working hard, composing a response that doesn't exist yet. When you finally sing, it should feel like exhaling something you've been holding. The conversation has a new dimension: think, then speak.",
      wrong: "If you're singing your response immediately after the guitar call with no internal hearing, you're doing regular call-and-response (which you already know from ss-4-3 and ss-4-6). The SILENCE between call and response is the whole point. If you can't hear a response internally, simplify: go back to two notes and shorter phrases until the inner ear catches up.",
      sarah: "Gene, think of those contemplative moments between phrases in Tinariwen or Hermanos Gutiérrez — the silence where the next musical thought is forming. That's audiation in the wild. You're making that process conscious. The desert blues backing track gives you the perfect spacious canvas for this inner work.",
      drone: { root: "Am", octave: 2, texture: "warm" },
      referencePitches: getPitchRange("A2", "G4"),
      pitchContour: true,
      metronome: 75,
      recorder: true,
      phraseForm: { pattern: "ABA", barsPerSection: 2, labels: { A: "Guitar Call", B: "Silent Audiation + Voice Response" } }
    },

    // ─── AUDIATION ENRICHMENT ───

    {
      id: "ss-4-24",
      time: 5,
      title: "Sing and Think — The Vanishing Melody",
      type: "vocal",
      what: "Beat omission: sing some notes aloud, audiate others silently in real time. This trains the ability to 'hear ahead' while performing — the bridge between 'hear before you sing' and 'hear while you play.' Choir directors call this the most powerful real-time audiation exercise.",
      setup: "Drone on A. Metronome at 70 BPM. No guitar needed.",
      drone: { root: "Am", octave: 2, texture: "pure" },
      referencePitches: getPitchRange("A2", "G4"),
      metronome: 70,
      steps: [
        { text: "Warm-up: sing A-C-D-E all aloud, one note per beat, quarter notes against the drone. Just four notes ascending. Feel the body map: A in the chest, C in the throat, D between throat and mask, E at the mask. Do this 4 times until it's automatic.", why: "Establishing the melodic pattern with full external sound gives your audiation something concrete to hold onto when notes start vanishing. The body map is your anchor." },
        { text: "First omission: sing A-C aloud, THINK D-E silently. Keep the beat — the silent notes occupy the same time as the sung ones. After the silence, sing A again. Did you land on the right A? The body should feel like it continued the upward journey (throat to mask) even during the silent notes.", why: "Beat omission — singing some notes while internally audiating others — trains real-time switching between external production and internal hearing. This is how experienced musicians 'hear ahead' while playing. The body map continues even through silence, giving you a somatic anchor." },
        { text: "More omission: sing A aloud, THINK C-D-E silently, sing A again. Only two notes are audible — the beginning and the end. Did you return to the same A? The internal journey (chest → throat → between → mask → back to chest) should feel vivid even though most of it was silent.", why: "Audiating three notes in real time while maintaining beat, pitch, and body awareness is a significant challenge. The return to A tests whether your internal tracking maintained the correct pitch level through the silent passage." },
        { text: "Full vanishing: sing A aloud → C-D-E-G all silent (four beats of internal singing) → A aloud again. The entire pentatonic ascending passage happens inside your head. Only the bookend As are audible. Did your inner ear carry the full journey?", why: "Four beats of silent pentatonic ascending is a demanding audiation task. But this is exactly what happens when a musician 'hears' a phrase internally before singing it — the music exists fully formed inside before any sound emerges. The bookend technique (sing-silence-sing) gives you immediate verification." },
        { text: "Creative application: make up a 4-note phrase from the pentatonic. Sing the first note aloud, think the middle two silently, sing the last note aloud. Try 5 different phrases. Which ones are easiest to hold internally? Stepwise motion (A-C-D-E) is usually easier than leaps (A-E-C-G).", why: "Applying beat omission to improvised phrases (rather than just scales) bridges the gap to real musical performance. Noticing which interval patterns are easier to audiate builds awareness of your inner ear's strengths." }
      ],
      feel: "The silent beats should feel FULL, not empty — your voice has stopped but your inner musician keeps singing. When you re-enter with sound and land on the right note, there's a satisfying click of confirmation.",
      wrong: "If you're humming or whispering during the 'silent' beats, you're bypassing the audiation. The entire point is internal hearing without sound. If landing on the return note is consistently wrong, simplify: omit only one note instead of two or three.",
      sarah: "Gene, this is what happens inside every great improviser's head — they're hearing music continuously even when they're not playing. The notes they DON'T play are just as audiated as the ones they do. You're building that continuous inner stream."
    },

    {
      id: "ss-4-25",
      time: 5,
      title: "The Groove Dropout — Can You Hold the Pocket?",
      type: "vocal",
      what: "The rhythm equivalent of the drone mute. The metronome plays, then goes silent. Can you hold the groove alive in your body through the silence and land back on the beat when it returns? This is rhythm audiation — internally generating pulse without external reinforcement.",
      setup: "Metronome at 80 BPM. Guitar optional. Backing track optional.",
      metronome: 80,
      tracks: [{ name: "Reggae One Drop 85", src: "/reggae-one-drop-85.mp3" }, { name: "Drums Only — Soul/Funk 90", src: "/drums-soul-funk-90.mp3" }],
      referencePitches: getPitchRange("A2", "G4"),
      steps: [
        { text: "Warm-up: strum Am on autopilot with the metronome at 80 BPM. Sing a simple pentatonic phrase — any notes, any rhythm. Lock into the groove for 1 minute. Feel where the pulse lives in your body — your foot, your head-nod, your breathing.", why: "Establishing a strong physical groove before the dropout ensures you have something to hold onto when the external reference disappears. The pulse should live in your body, not just your ears." },
        { text: "Rung 1 — 1 bar dropout: Count along with the metronome: 1-2-3-4, 1-2-3-4. On the third bar, STOP the metronome (or close your eyes and imagine it stops). Keep strumming and singing through 1 bar of silence (4 beats). Start the metronome again. Did you land on beat 1? Were you ahead or behind? Try 3 times.", why: "1 bar of rhythmic silence is the baseline — short enough to succeed but long enough to test whether your internal pulse is running independently. Most people drift slightly ahead (rushing) without external reinforcement." },
        { text: "Rung 2 — 2 bar dropout: Metronome plays 2 bars, goes silent for 2 bars, returns. Keep the groove alive through 8 beats of silence. Strum, sing, feel the pulse in your body. When the metronome returns, check: are you still in the pocket?", why: "2 bars doubles the cognitive load. Your internal clock must sustain tempo for twice as long without correction. The strumming provides a secondary rhythmic reference — your hands help your ear hold the time." },
        { text: "Rung 3 — 4 bar dropout: Metronome plays 2 bars, goes silent for 4 full bars (16 beats). This is HARD. Your foot becomes your anchor — keep it tapping. Sing through the silence. When the metronome returns after 4 bars... are you still there?", why: "4 bars of unsupported groove is the equivalent of the 20-second pitch hold — it pushes past what casual timing can sustain and into genuine rhythm audiation. The foot tap is your somatic anchor, just as the hand-on-chest was for pitch holds. Motor rhythm is more resilient than cognitive rhythm because it lives in the cerebellum and basal ganglia, which are less affected by cognitive load." },
        { text: "Try it with the backing track instead of the metronome: play the Reggae One Drop for 4 bars, pause it, sing and strum through 4 bars of silence, resume. The groove is richer — can you hold the entire feel (not just the tempo) in your body? The shuffle of the hi-hat, the weight of the one-drop on beat 3, the space on beat 1?", why: "Holding a full groove in silence is harder than holding just a tempo because a groove has feel, swing, and emphasis patterns beyond mere pulse. This is the rhythm equivalent of holding a triad vs. holding a single note — more information to maintain internally." },
        { text: "Stretch goal: no metronome, no backing track. From silence, generate a groove at ~80 BPM from your body alone. Foot tap, strum, sing. After 8 bars, start the metronome. How close is your internal tempo to 80? The gap is your current rhythm audiation accuracy.", why: "Generating tempo from silence — like generating pitch from silence — is the ultimate rhythm audiation test. Your body has absorbed 80 BPM through hours of practice. Now you're testing whether that absorption has become internalized enough to recall independently." }
      ],
      feel: "The dropout moments should feel like the ground disappearing — and then discovering you can still walk. When the metronome returns and you're right on the beat, there's a deep satisfaction: your internal clock works.",
      wrong: "If you consistently rush (land ahead of the returning metronome), your internal tempo is too fast — a common pattern under the slight anxiety of no reference. Try consciously slowing 5% during the silence. If you consistently drag (land behind), you may be losing energy without the external push — try keeping the foot tap slightly more emphatic during silence.",
      sarah: "Gene, this is the rhythm version of everything you've been doing with the drone. The drone taught your ear to hold pitch in silence. Now the groove dropout teaches your body to hold time in silence. Same principle, different domain. Every reggae musician you love has this skill — the one-drop only works if every player is generating beat 1 internally, together, without anyone playing it."
    }
  ]
};
